INSERT INTO public.questions VALUES ('8fa66e20-ce85-4cae-ab41-d87ef75e198b', 'e40608b2-002e-4803-830c-c7a04c2ace26', 'matrix', 'Questions 16–20', NULL, '<p data-start="895" data-end="975">Label the plan below.<br data-start="916" data-end="919">Choose the correct letter, <strong>A</strong>–<strong>H</strong></p>
<h3 data-start="977" data-end="1002"><img decoding="async" src="data:image/jpeg;base64," width="506" height="456" loading="lazy"></h3>
