INSERT INTO public.questions VALUES ('af50af10-bd93-4ac1-af20-45f55c32172e', 'c598392a-9e35-4e43-b3c1-f182f5b7b1e6', 'radio', 'Questions 11–16', NULL, '<p>Choose the correct answer.</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "the general operation of the camp"}, {"content": "the children who attend"}, {"content": "the job responsibilities"}], "question": "The speaker says that he is happy to answer questions during his talk about"}, {"correct": 2, "options": [{"content": "They like the fact that it is cheaper than other camps."}, {"content": "They are pleased with the wide range of facilities on offer."}, {"content": "They know their children will be looked after at the camp."}], "question": "Why do parents send their children to the camp again and again?"}, {"correct": 1, "options": [{"content": "the number of international students"}, {"content": "the preparation for professional sports"}, {"content": "the inclusion of non-sports activities"}], "question": "One special thing about this summer camp is"}, {"correct": 2, "options": [{"content": "who would like to work in the ofﬁce"}, {"content": "who have experience of cooking"}, {"content": "who young children can talk to"}], "question": "The speaker says that this year, the camp particularly needs people"}, {"correct": 0, "options": [{"content": "artistic talents"}, {"content": "good camera equipment"}, {"content": "a qualiﬁcation in photography"}], "question": "What should the new cameraperson have?"}, {"correct": 0, "options": [{"content": "Sports coaches earn the most."}, {"content": "Kitchen staff work the longest hours."}, {"content": "Cleaners work in the mornings and evenings."}], "question": "What does the speaker say about working conditions?"}]', 'null', 'null', 'null', '[{"content": "<h2 data-path-to-node=\"2\">PART 2</h2>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Speaker:</strong> Welcome to this talk about the UK Summer Sports Camp. I’m going to tell you about our summer sports camp for children and something about the children who come. Later on, I’ll tell you how to apply if you’d like to work with us this year. So please be patient.</p>\n<p data-path-to-node=\"4\">Feel free to interrupt if there’s anything you don’t understand about the <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"4\" data-index-in-node=\"74\">(11) way the camp is administered (A: general operation)</strong></span>, though if you could save any questions about the work itself until the end, that would be good.</p>\n<p data-path-to-node=\"5\">The UK Summer Sports Camp offers courses for kids aged six to 16, which focus on a wide range of sports and activities. Our aim is to provide a fun, safe experience for kids. The reason we’re successful is because <strong data-path-to-node=\"5\" data-index-in-node=\"214\">(<span style=\"text-decoration: underline; background-color: #ffe786;\">12) parents trust us and send their children to us summer after summer (C: know children will be looked after)</span></strong>. We aren’t the cheapest camp around, which might put some people off, but we make sure our team are caring and enthusiastic, and that’s why parents want their children to keep coming back, rather than because of the facilities on offer, great as they are, of course.</p>\n<p data-path-to-node=\"6\">We think our summer camp is special in a number of ways. We have students from all over the country, not just the local area. We run all the activities you’d expect in a summer camp—arts and music as well as sports—but we also have <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"6\" data-index-in-node=\"232\">(13) special coaching for those who might be able to make a career in their chosen sport (B: preparation for professional sports)</strong>.</span></p>\n<p data-path-to-node=\"7\">What will your role be if you come and work with us then? We need lots of people who are willing to teach the activities, but we also have non-coaching roles. What we particularly like this summer are <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"7\" data-index-in-node=\"201\">(14) people who are willing to be in charge of looking after our younger kids, making sure they’re happy and have someone to go to if they have any problems (C: young children can talk to)</strong></span>. We usually need a few cooks too, though we don’t need anyone extra for our office at the moment.</p>\n<p data-path-to-node=\"8\">This year, I’m very pleased to introduce a new role at the camp: camera person. We need someone with great video and photography skills to record the fun everyone has. We’ll supply first-class equipment, but we <strong data-path-to-node=\"8\" data-index-in-node=\"211\">(<span style=\"text-decoration: underline; background-color: #ffe786;\">15) need you to supply your creative abilities (A: artistic talents)</span></strong>. If you’re interested in this role, come and talk to me at the end.</p>\n<p data-path-to-node=\"9\">Now you probably want to know about working conditions, hours and pay. This depends on your role. You can choose to work daytimes, evenings or weekends. <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"9\" data-index-in-node=\"153\">(16) Daytime coaching roles pay the highest wages (A: sports coaches earn the most)</strong> </span>because of the sports skills required and the longer hours. If you choose to work in the kitchen, your hours of work will be either at breakfast and lunch or at dinner. Cleaners work in the mornings before the camp activities start at 10:00 am, so not too early.</p>\n<hr data-path-to-node=\"10\" />\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Speaker:</strong> If you do work with us, there are lots of benefits in addition to the money. Whether you’re teaching a sport or not, you’ll be <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"11\" data-index-in-node=\"136\">(17/18) given access to all our facilities (C: use of sports facilities)</strong> </span>which means you can have a swim or play a football match without having to pay anything.</p>\n<p data-path-to-node=\"12\">We have an internet cafe where there’s a small charge for access, and we also provide discounted meals in our canteen. We’ll <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"12\" data-index-in-node=\"125\">(17/18) give everyone UK Summer Camp T-shirts (B)</strong></span>, which we’ll expect you to wear when working, and if you wish we also have some cool sports bags which are available for a small fee.</p>\n<p data-path-to-node=\"13\">So what do we expect from you? You’ll be glad to hear that we don’t need to see any formal certificates. If you’ve worked with kids before, that would be an advantage but it isn’t essential. Of course, you need to <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"13\" data-index-in-node=\"214\">(19/20) be sociable and enjoy meeting people (C: a friendly personality)</strong>. </span>There’ll always be a supervisor available who you should talk to before making any important decisions. We <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"13\" data-index-in-node=\"395\">(19/20) can’t accept applications from people under the age of 18 (E: to be over a certain age)</strong></span> I’m afraid, but if you haven’t got there yet, don’t worry, there’s always next time.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('445237b7-bac9-4b97-aaf3-c963ae74c92b', '9b5fa1f7-381a-4bdd-83b9-c52eaf9908f3', 'radio', 'Questions 21-25', NULL, '<p>Choose the correct letter, <strong>A</strong>,<strong>B </strong>or <strong>C</strong></p>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p><strong>Song-writing course for drama students</strong></p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "A. listing the references"}, {"content": "B. keeping to the word limit"}, {"content": "C. writing the evaluation"}], "question": "What problem is Lorna having with her report?"}, {"correct": 2, "options": [{"content": "A. to improve hisjob prospects"}, {"content": "B. to increase his self-confidence"}, {"content": "C. to develop his self-expression"}], "question": "Why did Charles take the song-writing course?"}, {"correct": 2, "options": [{"content": "A. individual work"}, {"content": "B. pair work"}, {"content": "C. group work"}], "question": "Which type of work did Lorna most enjoy?"}, {"correct": 0, "options": [{"content": "A. song structure"}, {"content": "B. writing a chorus"}, {"content": "C. lyrical styles and forms"}], "question": "Which aspect of the course content did both students find interesting?"}, {"correct": 1, "options": [{"content": "A. impossible"}, {"content": "B. tiring"}, {"content": "C. amusing"}], "question": "Lorna found writing a song"}]', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 3: SONGWRITING COURSE DISCUSSION</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Lorna:</strong> Hi Charles. I’m writing my report on the songwriting course for drama students. You know, the one-week residential course for drama students from different universities, where you learn about writing songs. You did that course last year, didn’t you? Could you give me some tips for the report? I’m having a few problems with it.</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Charles:</strong> Yes, it was great. Well Lorna, you could start by thinking about what you got out of it.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Lorna:</strong> Hmm, evaluating how useful it was is simple. <strong data-path-to-node=\"5\" data-index-in-node=\"52\">(21) The challenge is not to go over length [Answer: B – word limit]</strong>.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Charles:</strong> Hmm, referring to published sources might help. That would make it more scholarly too.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Lorna:</strong> OK, I’ll go with that. And saying why you did the songwriting course is important. Some people just do it as another string to their bow, to help with auditions for work and things.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Charles:</strong> <strong data-path-to-node=\"8\" data-index-in-node=\"9\">(22) I thought it was a good opportunity to try out new techniques for communicating feelings and emotions [Answer: C – self-expression]</strong>. I was already confident about singing before I did it.</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Lorna:</strong> I thought it was the location of the course which made it special—being held in a country house rather than in a university. They were doing some building work on part of the house though, so it wasn’t always easy to concentrate. I enjoyed the workshop most. How about you?</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Charles:</strong> Well, <strong data-path-to-node=\"10\" data-index-in-node=\"15\">(23) we were divided into 6 small groups for the afternoon, each with their own advisor. That was the best bit for me [Answer: C – group work]</strong>, having that discussion with an expert. When we got into pairs to start writing our songs, the idea was to combine people with different levels of knowledge and experience, but my partner preferred working on her own generally.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Lorna:</strong> Hmm, and what did you think of the course content? <strong data-path-to-node=\"11\" data-index-in-node=\"58\">(24) I hadn’t realized before how important the structure of a song is to its success.</strong></p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Charles:</strong> <strong data-path-to-node=\"12\" data-index-in-node=\"9\">Yes, we learned it’s no use writing the most beautiful words and melodies if there’s no shape [Answer: A – song structure]</strong>.</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Lorna:</strong> Hmm, and we learned about the importance of a chorus in a song. I knew about that stuff from my singing classes. It’s a bit obvious, isn’t it?</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Charles:</strong> I suppose so. It was the input on lyrical styles and forms that I found tedious. You could always look them up on the web anyway. How did you get on with writing your song?</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Lorna:</strong> It was tough and Peggy, my partner, was hard work, which wasn’t funny, and writing was a slow process as a result of our lack of communication. <strong data-path-to-node=\"15\" data-index-in-node=\"151\">(25) By the time we finished, I was exhausted [Answer: B – tiring]</strong>.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Charles:</strong> Writing music from the heart is like that, especially by the end of a course.</p>\n<hr data-path-to-node=\"17\" />\n<h3 data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">DRAMA WORKSHOPS (Questions 26-30)</strong></h3>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Lorna:</strong> Well, that’s got the report sorted, thanks. Have you decided which teacher’s workshops you’re going to do next term? I want to do Bob Lacey’s. He’s got a brilliant reputation for voice coaching, you know, <strong data-path-to-node=\"19\" data-index-in-node=\"212\">(26) getting us to use dialects and different pronunciation and stuff [Answer: G – using a range of accents]</strong>. He gets you to do things like read out a newspaper article in character. Ha ha, it’s amazing.</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Charles:</strong> I’m thinking of going to Evelyn Chance’s workshop.</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Lorna:</strong> Oh, Evelyn! She’s quite a character. Is she running the stage fights course again?</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Charles:</strong> Yes, fencing and pretend punches and throwing techniques. <strong data-path-to-node=\"22\" data-index-in-node=\"67\">(27) She really knows how to help actors use the whole of the space available [Answer: B – full use of the stage]</strong>.</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Lorna:</strong> Lots of people like Ted Winter’s workshop. He knows how to deliver. <strong data-path-to-node=\"23\" data-index-in-node=\"75\">(28) He’s keen on actors conveying emotion through their bodies and faces alone [Answer: D – physical expression]</strong>. It’s a great way to reveal complex relationships and situations to an audience without making a speech of any kind. I’m definitely going to sign up for that one.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Charles:</strong> If you want to understand a director’s ideas, Kevin Gray’s workshop would be perfect for you. He likes telling people what to do and he’s always saying you can’t have a company of actors reading a play any way they want because they’d end up fighting amongst themselves. <strong data-path-to-node=\"24\" data-index-in-node=\"280\">(29) They must listen to the director [Answer: H – following instructions]</strong>.</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Lorna:</strong> What about Dorothy Thomas? <strong data-path-to-node=\"25\" data-index-in-node=\"34\">(30) She’s good at activities for getting rid of stress and, you know, emptying your mind of all thoughts [Answer: C – relaxation techniques]</strong> about the past, and that can really help when acting.</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Charles:</strong> Hmm, well, I think I’ll put my name down for…</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('fa567da3-6e28-4b5a-b2e0-3db9db02dae6', 'c598392a-9e35-4e43-b3c1-f182f5b7b1e6', 'checkbox', 'Questions 17–18', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>Which <strong>TWO </strong>beneﬁts are provided free of charge to camp workers?</p>
', 'multiple_choice_many', 'null', '[{"option": "a sports bag", "correct": false}, {"option": "a T-shirt", "correct": true}, {"option": "use of sports facilities", "correct": true}, {"option": "meals", "correct": false}, {"option": "internet access", "correct": false}]', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('55b2ef30-a3fe-4722-97ec-6b41abc2961c', '21dc2b9b-9c21-41be-ac7f-bd2e50feda7a', 'radio', 'Questions 21-26', NULL, '<p>Choose the correct answers</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "a cheaper product."}, {"content": "more hygienic in its effects."}, {"content": "a different kind of commodity."}], "question": "Janet says that over time, shampoo has become"}, {"correct": 0, "options": [{"content": "They really do exist."}, {"content": "Women worry about them more than men."}, {"content": "Their name is inaccurate."}], "question": "What does Janet say about ‘bad hair days’?"}, {"correct": 2, "options": [{"content": "All shampoos contain the same chemicals."}, {"content": "The chemicals are believed to be dangerous."}, {"content": "The presence of the chemicals is rarely publicised."}], "question": "What do Janet and Michael say about the chemicals used in shampoos?"}, {"correct": 1, "options": [{"content": "costs more."}, {"content": "looks less attractive."}, {"content": "takes a lot longer."}], "question": "According to Janet, printing directly onto shampoo bottles, rather than onto labels,"}, {"correct": 1, "options": [{"content": "the appearance of shampoo bottles."}, {"content": "variations in the weight of shampoo bottles."}, {"content": "the source of recycled plastic in shampoo bottles."}], "question": "With regard to environmental issues, Michael and Janet want to investigate"}, {"correct": 2, "options": [{"content": "loyalty to certain brands."}, {"content": "desire to get value for money."}, {"content": "willingness to try new products."}], "question": "Michael bases his own shampoo purchase decisions on his"}]', 'null', 'null', 'null', '[{"content": "<h2 data-path-to-node=\"2\">PART 3</h2>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Michael:</strong> Hi Janet, how are you getting on with the shampoo marketing project?</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Janet:</strong> Hi Michael. Uh, it’s interesting. I’ve read how shampoo marketing has developed over the last hundred years.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Michael:</strong> Oh, I didn’t think we needed to do that.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Janet:</strong> True, but I’m interested anyway. Basically, what was once sold as an economical way of getting your hair clean has <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"6\" data-index-in-node=\"122\">(21) evolved into a beauty product (C: a different kind of commodity)</strong>.</span></p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Michael:</strong> Right. And shampoo is interesting because it’s a key influence in how we see ourselves. You’ve heard of “bad hair days”—when your hair looks bad, maybe you didn’t wash it and you feel bad about it.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Janet:</strong> Heard of them, yes. Had one? No. I don’t think they’re real, bad hair days…</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Michael:</strong> Come on!</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Janet:</strong> Well, whatever you want to call them, that’s not what research from Yale is suggesting. <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"10\" data-index-in-node=\"95\">(22) They’re not just imagined, and both sexes are equally affected by them (A: They really do exist)</strong>. </span>And when they happen, people tend to perform and feel worse than usual.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Michael:</strong> Right. And I’ve been reading about shampoo ingredients—chemicals like sodium lauryl sulfate, methyl chloride. Many of the manufacturers tend to use these, or others like them, though<span style=\"text-decoration: underline;\"> <span style=\"background-color: #ffe786;\"><strong data-path-to-node=\"11\" data-index-in-node=\"192\">(23) they keep it quiet (C: rarely publicised)</strong>.</span></span></p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Janet:</strong> Right. When it comes to the product <span class=\"citation-126 citation-127 citation-end-127\">packaging, they’re strangely silent about it. Another area it would be interesting to investigate is the labeling on bottles. Apparently, printing directly onto the bottles costs about 50% less than sticking a printed label on, because it’s </span><span class=\"citation-126 citation-end-126\">a much quicker process. But manufacturers are lukewarm </span>about this because <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"12\" data-index-in-node=\"358\">(24) it doesn’t enhance the visual impact of the bottle—it comes across as a bit cheap (B: looks less attractive)</strong></span>.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Michael:</strong> Hmm. We need to think about environmental issues. I was surprised how little recycled plastic goes into the bottles. I think it’s because light-colored plastic is more difficult to make from recycled stuff.</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Janet:</strong> Yeah, but manufacturers can make their packaging more environmentally friendly just by <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"14\" data-index-in-node=\"94\">(25) making it less heavy. I’d like to find out whether some of them actually do (B: variations in the weight)</strong> </span>when we do the research.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Michael:</strong> Yes, that’s worth looking into. Thinking about you as a customer, what’s important when choosing shampoo?</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Janet:</strong> Hmm. I’m always wary of special offers. When something’s flagged as being half price, it rarely is really.</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Michael:</strong> But <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"17\" data-index-in-node=\"13\">(26) if there’s a make I’ve never seen before, I’m usually up for giving it a go (C: willingness to try new products)</strong></span>, rather than sticking to one or two favourite brands all my life.</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Janet:</strong> Interesting.</p>\n<hr data-path-to-node=\"19\" />\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Michael:</strong> Shall we discuss some of these shampoo advertisements then and try and identify what sort of psychological response each one is trying to get from the viewer?</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Janet:</strong> Okay. What about Zing?</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Michael:</strong> Well, it should probably appeal equally to men and women. In the ad we see this happy family, lovely home, healthy, good-looking children with clean hair obviously.</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Janet:</strong> Yes, and I think we’re supposed to watch the ad and think, “Wow, if only my life was like that.” Yeah, I know what you mean. I think the advertisers want the viewers to almost <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"23\" data-index-in-node=\"183\">(27) wish they were the people in the ad (B: enviable lifestyle)</strong>.</span></p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Michael:</strong> Sure. I mean, that’s very common in advertising, but not universal. Hmm. You know that ad for <strong data-path-to-node=\"24\" data-index-in-node=\"103\">Splash</strong> shampoo? That lasts about five minutes, and where there’s a story?</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Janet:</strong> Oh yes, the commercial about the <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"25\" data-index-in-node=\"40\">(28) couple… and all through the commercial, it’s not clear if they’re going to break up or stay together (F: romantic interest)</strong></span>. Exactly. Well, I think the marketing’s been done very cleverly there.</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Michael:</strong> I don’t think we’re supposed to want to be the characters in the commercial, but we’re supposed to get to know them a bit.</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Janet:</strong> Yes, well, I thought the story was effective. You’re glad to learn when it’s over that they’re obviously going to stay together.</p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Michael:</strong> Hmm, maybe. I suppose some manufacturers don’t want to bore people with all the science.</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Janet:</strong> Sure. And then there’s the Just go advertisement.</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Michael:</strong> Yes, that had lots of technical information about what the shampoo actually consists of. I suppose they want customers to<span style=\"text-decoration: underline;\"> <span style=\"background-color: #ffe786;\"><strong data-path-to-node=\"30\" data-index-in-node=\"131\">(29) feel confident that when they buy Just go, they are at least making an informed decision (E: product reliability)</strong>.</span></span></p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Janet:</strong> Yes, they’re buying something that will do the job they want it to. That’s it. I’ve read one of the most effective shampoo ads in recent times was the one for Brozene.</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Michael:</strong> Yes, but there’s no commentary, just images of the shampoo and lots of clean hair. Haha! I suppose the effect though is <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"32\" data-index-in-node=\"129\">(30) very calming, with soft music and very peaceful imagery (A: link to relaxation)</strong></span>.</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Janet:</strong> Yes, but at the end of the ad, we’ve hardly learned anything about the product, have we?</p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Michael:</strong> I suppose not. But isn’t it interesting how much the ads for what are essentially very similar products vary so much?</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('56b31f60-7e65-445f-a1ef-02a3782f7c2e', '21dc2b9b-9c21-41be-ac7f-bd2e50feda7a', 'matching', 'Questions 27-30', '', '<p>According to the speakers, what is the main advertising focus of each of the following shampoo advertisements?</p>
<p>Choose <strong>FOUR </strong>answers from the box and write the correct letter, <strong>A-G</strong>, next to questions 27-30.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Advertising focuses</strong></p>\n<p> </p>\n<p>Zing {enviable lifestyle}</p>\n<p> </p>\n<p>Splash {romantic interest}</p>\n<p> </p>\n<p>Just go {product reliability}</p>\n<p> </p>\n<p>Brozene  {link to relaxation}</p>", "answerOptions": [{"optionText": "link to relaxation"}, {"optionText": "enviable lifestyle"}, {"optionText": "natural ingredients"}, {"optionText": "masculine image"}, {"optionText": "product reliability"}, {"optionText": "romantic interest"}, {"optionText": "use by celebrities"}], "matchingItems": []}', 'null', '[{"content": "<p>1</p>"}]', 1);
INSERT INTO public.questions VALUES ('123a4723-e131-4383-8bd3-a0589c14afc6', '396fdc93-9f96-466a-825c-dd4e4e8fca75', 'radio', 'Questions 11 – 15', NULL, '<p>Choose the correct answer.</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "A birds that are now endangered."}, {"content": "B birds from all over the world."}, {"content": "C birds that are common in the local area."}], "question": "The speaker stresses the importance to Clifton Bird Park of"}, {"correct": 1, "options": [{"content": "A must work at weekends."}, {"content": "B need to come at least once a month."}, {"content": "C will only be required in the busy season."}], "question": "People who volunteer to help with gardening at the park"}, {"correct": 1, "options": [{"content": "A someone who can work independently"}, {"content": "B someone who is willing to work in any weather"}, {"content": "C someone who knows a lot about plants"}], "question": "According to the speaker, who would be the ideal gardening volunteer?"}, {"correct": 0, "options": [{"content": "A international visitors."}, {"content": "B local people from Clifton."}, {"content": "C school groups."}], "question": "Volunteer guides will mainly be working with"}, {"correct": 1, "options": [{"content": "A food and drink"}, {"content": "B transport"}, {"content": "C tools"}], "question": "What is still required for the Maintenance Day at the bird park?"}]', 'null', 'null', 'null', '[{"content": "<h2 data-path-to-node=\"2\">SECTION 2</h2>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Sandra:</strong> Hello. My name is Sandra Haze and I’m from Clifton Bird Park. It’s great to see so many possible volunteers here. The park is now a very popular attraction in this area. I think people love coming to see so many different types of birds in a beautiful environment. For some species that we have here, <strong data-path-to-node=\"3\" data-index-in-node=\"309\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(11) there aren’t many still alive in the wild, so a big part of our job is to make sure we help their numbers increase </span><span style=\"background-color: #f1c40f;\"><span style=\"text-decoration: underline;\">(A: endangered</span>)</span></strong>. All the birds are native species.</p>\n<p data-path-to-node=\"4\">We need volunteers to help the bird park officers with different jobs. One of these is gardening. Obviously, summer is the time when we have most visitors, but the park needs looking after all year round. If you want to help you can choose which day, although we do already have plenty of volunteers working Saturdays and Sundays, but <strong data-path-to-node=\"4\" data-index-in-node=\"335\"><span style=\"text-decoration: underline;\"><span style=\"background-color: #f1c40f;\">(12) one day every four weeks is the minimum commitment (B: once a month)</span></span></strong> that we ask for.</p>\n<p data-path-to-node=\"5\">So who’s the ideal volunteer for gardening work? If you have expert knowledge about flowers and trees, great, but we’re looking more for people who are flexible and <strong data-path-to-node=\"5\" data-index-in-node=\"165\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(13) turn up no matter whether it’s raining or baking hot (B: in any weather)</span></strong>. That’s what’ll make you the best person for the job. It’s all teamwork so you’ll have plenty of support.</p>\n<p data-path-to-node=\"6\">What about volunteer guides? A guide’s role is to point out the birds and talk about the conservation program in general. It’s <strong data-path-to-node=\"6\" data-index-in-node=\"127\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(14) people in a foreign tour group (A: international visitors)</span></strong> that you’re responsible for. The Clifton residents who come to the park usually know their way around. We get a few teachers bringing in classes, but they’re the park officer’s responsibility.</p>\n<p data-path-to-node=\"7\">The last thing to mention is the park’s maintenance day, which is coming up soon. We’re hoping to get as many volunteers as possible to come and help tidy things up. <strong data-path-to-node=\"7\" data-index-in-node=\"166\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(15) If anyone is able to drive some other volunteers to the event, please let me know because we need help there (B: transport)</span></strong>. The park officers will provide you with spades and drills and hammers, all of that stuff, and they’ll be offering you some refreshments too, so it should be a good day out.</p>\n<hr data-path-to-node=\"8\" />\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Sandra:</strong> So here’s a map of Clifton Bird Park. As you can see, the railway line runs along the northwest of the park and road access is on that side too, from Clifton Lane. We want volunteers to work on a few different areas on maintenance day which is coming up soon.</p>\n<p data-path-to-node=\"10\">Firstly the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"10\" data-index-in-node=\"12\">(16) wooden bridge</strong></span>. I’ll explain where that is. You can see Clifton Lane and the main gate into the park. On the southern side of Clifton Lane is one of our car parks and below that, there are two similar sized ponds. The wooden bridge runs <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"10\" data-index-in-node=\"253\">between those two ponds (F)</strong></span>. We just need to make it a bit stronger.</p>\n<p data-path-to-node=\"11\">Some volunteers will be doing a bit of painting at the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"55\">(17) observation tower</strong></span>. The tower’s in the southeast corner of the map. You see there are two different sized ponds there. The tower’s on the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"197\">south side of the larger pond at the end of the path (H)</strong></span>. We’ll need about three people to help out.</p>\n<p data-path-to-node=\"12\">We need to replace the windows on the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"38\">(18) visitor cabins</strong></span>. So on the map you can see our car park on the north side of Clifton Lane. There’s the woods, and on the left hand side of the map the railway line. The visitors cabins are marked there, <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"245\">between the woods and the railway station (C)</strong></span>.</p>\n<p data-path-to-node=\"13\">You’ll also be repairing some <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"13\" data-index-in-node=\"30\">(19) nesting boxes</strong></span>. See the picnic area? The path you want is between there and the big pond. Follow it round all the way to the end. So as we’re looking at the map now, the nesting boxes are on the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"13\" data-index-in-node=\"229\">right of that pond (E)</strong></span>.</p>\n<p data-path-to-node=\"14\">Finally the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"14\" data-index-in-node=\"12\">(20) boat sheds</strong></span>. Towards the top of the map, you’ve got that smallish pond quite near the railway line, and there are two places marked up there. The boat sheds are on the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"14\" data-index-in-node=\"184\">same side of the pond as the woods (B)</strong></span>, not the place marked at the top of the park. What we want you to do…</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('3a7fe39c-8e22-43b6-aedc-3fc323ff7aaf', '4207ab5a-bffb-4788-ae89-6367d6c8a524', 'fillup', 'Questions 6-13', '<p><strong>Complete the sentences below.</strong></p>
<p>Choose <strong>ONE WORD ONLY</strong> from the passage for each answer. Write your answers in boxes 6-13 on your answer sheet.</p>
<p>In France, people started to overcome their disgust about potatoes because the King put a potato {flower} in his buttonhole.</p>
<p>Frederick realised the potential of potatoes but he had to handle the {prejudice}against potatoes from ordinary people.</p>
<p>The King of Prussia adopted some {reverse} psychology to make people accept potatoes.</p>
<p>Before 1800, the English people preferred eating {meat} with bread, butter and cheese.</p>
<p>The obvious way to deal with England food problems was to grow high yielding potato {crops}</p>
<p>The Irish {soil} and climate suited potatoes well.</p>
<p>Between 1780 and 1841, based on the {cultivation} of the potatoes, the Irish population doubled to eight million.</p>
<p>The potato’s high yields helped the poorest farmers to produce much healthier food almost without {investment} or hard physical work.</p>
', NULL, 'fill-in-the-blank', 'null', 'null', 'null', 'null', '[{"content": "<p>6. In France, people started to overcome their disgust about potatoes because the King put a potato <strong>flower</strong> in his buttonhole.</p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong class=\"\">Đáp án:</strong> <strong class=\"\">flower</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn 6) “…</span><span class=\"\">Louis XVI began to sport a potato </span><strong class=\"\">flower</strong><span class=\"\"> in his buttonhole…</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong class=\"\">Giải thích:</strong><span class=\"\"> Vua Louis XVI cài hoa khoai tây (potato flower) lên áo để khuyến khích dân chúng chấp nhận.</span></p>\n</li>\n</ul>\n<p>7. Frederick realised the potential of potatoes but he had to handle the <strong>prejudice</strong> against potatoes from ordinary people.</p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong class=\"\">Đáp án:</strong> <strong class=\"\">prejudice</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn 7) “…</span><span class=\"\">Frederick the Great of Prussia saw the potato’s potential…</span><span class=\"\"> but faced the challenge of overcoming the </span><strong class=\"\">people’s prejudice</strong> against the plant.”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong>Giải thích:</strong> Vua Phổ phải đối mặt với định kiến/thành kiến (prejudice) của dân chúng.</p>\n</li>\n</ul>\n<p>8. The King of Prussia adopted some <strong>reverse</strong> psychology to make people accept potatoes.</p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong>Đáp án:</strong> <strong>reverse</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 7) “Trying a less direct approach to encourage his subjects to begin planting potatoes, Frederick used a bit of <strong>reverse psychology</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"19,2,0\"><strong>Giải thích:</strong> Frederick đã dùng tâm lý ngược (reverse psychology) để dụ dân chúng ăn cắp khoai tây về trồng.</p>\n</li>\n</ul>\n<p>9. Before 1800, the English people preferred eating <strong>meat</strong> with bread, butter and cheese.</p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong>Đáp án:</strong> <strong>meat</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 8) “Prior to 1800, the English diet had consisted primarily of <strong>meat</strong>, supplemented by bread, butter and cheese.”</p>\n</li>\n<li>\n<p data-path-to-node=\"21,2,0\"><strong>Giải thích:</strong> Chế độ ăn chủ yếu của người Anh trước 1800 là thịt (meat).</p>\n</li>\n</ul>\n<p>10. The obvious way to deal with England food problems was to grow high yielding potato <strong>crops</strong>.</p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong>Đáp án:</strong> <strong>crops</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 8) “High-yielding, easily prepared potato <strong>crops</strong><span class=\"animating\"> were the obvious solution to England’s food problems.</span>“</p>\n</li>\n<li>\n<p data-path-to-node=\"23,2,0\"><strong>Giải thích:</strong> Các vụ mùa khoai tây cho năng suất cao là giải pháp rõ ràng cho vấn đề lương thực.</p>\n</li>\n</ul>\n<p>11. The Irish <strong>soil</strong> and climate suited potatoes well.</p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong>Đáp án:</strong> <strong>soil</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 9) “The potato was well suited to the Irish <strong>soil</strong> and climate…”</p>\n</li>\n<li>\n<p data-path-to-node=\"25,2,0\"><strong>Giải thích:</strong> Đất đai (soil) và khí hậu Ireland rất phù hợp với khoai tây.</p>\n</li>\n</ul>\n<p>12. Between 1780 and 1841, based on the <strong>cultivation</strong> of the potatoes, the Irish population doubled to eight million.</p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong>Đáp án:</strong> <strong>cultivation</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 10) “The Irish population doubled to eight million between 1780 and 1841, without any significant expansion of industry or reform of agricultural techniques beyond the widespread <strong>cultivation</strong> of the potato.”</p>\n</li>\n<li>\n<p data-path-to-node=\"27,2,0\"><strong>Giải thích:</strong> Sự gia tăng dân số dựa trên việc trồng trọt/canh tác (cultivation) khoai tây rộng rãi.</p>\n</li>\n</ul>\n<p>13. The potato’s high yields helped the poorest farmers to produce much healthier food almost without <strong>investment</strong> or hard physical work.</p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong>Đáp án:</strong> <strong>investment</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 10) “…the potato’s high yields allowed even the poorest farmers to produce more healthy food than they needed with scarcely any <strong>investment</strong> or hard labour.”</p>\n</li>\n<li>\n<p data-path-to-node=\"29,2,0\"><strong>Giải thích:</strong> Năng suất cao của khoai tây giúp nông dân nghèo không cần đầu tư (investment).</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('09fe948b-432b-4474-8077-e3e68817813a', '1793f174-7dcb-4b5a-aea5-f256f19b3302', 'radio', 'Questions 21–26', '', '<p data-start="126" data-end="167"><strong data-start="126" data-end="167">Choose the correct letter, A, B or C.</strong></p>
<p data-start="169" data-end="204"><span style="font-size: 12pt;"><strong>Project on Theatre Programmes</strong></span></p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "A was not familiar to their module leader"}, {"option_text": "B had not been chosen by other students"}, {"option_text": "C did not prove to be too difficult to research"}], "question": "Finn was pleased to discover that their topic"}, {"correct": 0, "options": [{"option_text": "A theatres pay companies to produce them"}, {"option_text": "B few theatre-goers buy them nowadays"}, {"option_text": "C they contain far more adverts than previously"}], "question": "Maya says a mistaken belief about theatre programmes is that"}, {"correct": 2, "options": [{"option_text": "A were difficult for audiences to obtain"}, {"option_text": "B were given out free of charge"}, {"option_text": "C were seen as a kind of contract."}], "question": "Finn was surprised that, in early British theatre, programmes"}, {"correct": 0, "options": [{"option_text": "A promoted their own plays."}, {"option_text": "B performed plays outdoors."}, {"option_text": "C had to tour with their plays."}], "question": "Maya feels their project should include an explanation of why companies of actors"}, {"correct": 2, "options": [{"option_text": "A were more original."}, {"option_text": "B were more colourful."}, {"option_text": "C were more informative."}], "question": "Finn and Maya both think that, compared to nineteenth-century programmes, those from the eighteenth century"}, {"correct": 1, "options": [{"option_text": "A very few theatre programmes were printed in the USA."}, {"option_text": "B British theatre programmes failed to develop for so long."}, {"option_text": "C theatre programmes in Britain copied fashions from the USA."}], "question": "Maya doesn’t fully understand why, in the twentieth century,"}]', 'null', 'null', 'null', '[{"content": "<h3 data-section-id=\"suogjm\" data-start=\"57\" data-end=\"67\">PART 3</h3>\n<p data-start=\"69\" data-end=\"189\"><strong data-start=\"69\" data-end=\"78\">MAYA: </strong>So Finn, I’ve done as much as I can for our project on theatre programmes. How’s your research coming along?</p>\n<p data-start=\"191\" data-end=\"527\"><strong data-start=\"191\" data-end=\"200\">FINN: </strong>OK, Maya. I didn’t know theatre programmes are called playbills in the USA till I started looking into the topic. Even though I struggled to find many useful websites, I’m glad we picked this subject. <span style=\"background-color: #f3db7b;\">No one else on the course is doing the same as us, although it is one of the research areas of the module convenor. <strong data-start=\"520\" data-end=\"527\">Q21</strong></span></p>\n<p data-start=\"529\" data-end=\"581\"><strong data-start=\"529\" data-end=\"538\">MAYA: </strong>That might actually put some people off.</p>\n<p data-start=\"583\" data-end=\"708\"><strong data-start=\"583\" data-end=\"592\">FINN: </strong>I suppose so. Anyway, I hadn’t realised there are actually companies specialising in creating theatre programmes.</p>\n<p data-start=\"710\" data-end=\"1013\"><strong data-start=\"710\" data-end=\"719\">MAYA: </strong>Yes, they’re quite common nowadays. Contrary to what many people think, <span style=\"background-color: #f3db7b;\">theatres don’t hire people to do the programmes.<strong data-start=\"1006\" data-end=\"1013\">Q22</strong> </span>In fact companies buy the rights to publish programmes on the theatre’s behalf – and then make their money selling advertising space within the programme booklet. </p>\n<p data-start=\"1015\" data-end=\"1076\"><strong data-start=\"1015\" data-end=\"1024\">FINN: </strong>It must be easier for theatres to do it that way.</p>\n<p data-start=\"1078\" data-end=\"1094\"><strong data-start=\"1078\" data-end=\"1087\">MAYA: </strong>Yes.</p>\n<p data-start=\"1096\" data-end=\"1228\"><strong data-start=\"1096\" data-end=\"1105\">FINN: </strong>I remember reading something about programmes in early British theatre. It said that the cast was always very important.</p>\n<p data-start=\"1230\" data-end=\"1335\"><strong data-start=\"1230\" data-end=\"1239\">MAYA: </strong>Yeah, audiences were very familiar with leading actors, and big names would draw huge crowds.</p>\n<p data-start=\"1337\" data-end=\"1641\"><strong data-start=\"1337\" data-end=\"1346\">FINN: </strong>But I hadn’t realised that if the programme named a famous actor, that’s who the public expected to perform. And if that didn’t happen, <span style=\"background-color: #f3db7b;\">people accused the theatre of breaking their agreement with the audience <strong data-start=\"1634\" data-end=\"1641\">Q23</strong>.</span> They would demand refunds, and, if they didn’t get them, there were riots! </p>\n<p data-start=\"1643\" data-end=\"1691\"><strong data-start=\"1643\" data-end=\"1652\">MAYA: </strong>Outrageous. That’d never happen now.</p>\n<p data-start=\"1693\" data-end=\"1808\"><strong data-start=\"1693\" data-end=\"1702\">FINN: </strong>No, people are too polite, even when they’re disappointed if the star of the show misses a performance.</p>\n<p data-start=\"1810\" data-end=\"2231\"><strong data-start=\"1810\" data-end=\"1819\">MAYA: </strong>We should definitely include that information about early audiences in our project.<span style=\"background-color: #f3db7b;\"> I also think it’s important to mention that lots of ordinary people at that time were illiterate, so theatre programmes were of limited value in advertising plays. When a company of actors arrived in a town, they’d parade around the streets in their costumes, beating drums and announcing their upcoming performances. <strong data-start=\"2224\" data-end=\"2231\">Q24</strong></span></p>\n<p data-start=\"2238\" data-end=\"2308\"><strong data-start=\"2238\" data-end=\"2247\">FINN: </strong>Interesting. I couldn’t imagine that happening now either.</p>\n<p data-start=\"2310\" data-end=\"2422\"><strong data-start=\"2310\" data-end=\"2319\">MAYA: </strong>There’s also an interesting comparison to make between eighteenth and nineteenth-century programmes.</p>\n<p data-start=\"2424\" data-end=\"2533\"><strong data-start=\"2424\" data-end=\"2433\">FINN: </strong>Wasn’t it in the nineteenth century that theatre programmes started to resemble programmes today?</p>\n<p data-start=\"2535\" data-end=\"2628\"><strong data-start=\"2535\" data-end=\"2544\">MAYA: </strong>Yes. And, unlike programmes from the eighteenth century, they always used colour.</p>\n<p data-start=\"2630\" data-end=\"2841\"><strong data-start=\"2630\" data-end=\"2639\">FINN: </strong>And there was a greater variety of designs<span style=\"background-color: #f3db7b;\">. But personally, I think eighteenth-century programmes were superior because they told the theatre-goers so many things, <strong data-start=\"2834\" data-end=\"2841\">Q25</strong> </span>including about the actors. </p>\n<p data-start=\"2843\" data-end=\"2925\"><strong data-start=\"2843\" data-end=\"2852\">MAYA:  </strong>And about the writer, the plot, and sometimes the history of the play.</p>\n<p data-start=\"2927\" data-end=\"3024\"><strong data-start=\"2927\" data-end=\"2936\">FINN: </strong>That’s right. … What should we say about theatre programmes in the twentieth century?</p>\n<p data-start=\"3026\" data-end=\"3131\"><strong data-start=\"3026\" data-end=\"3035\">MAYA: </strong>I reckon the most important thing is the dramatic change they underwent during World War Two.</p>\n<p data-start=\"3133\" data-end=\"3206\"><strong data-start=\"3133\" data-end=\"3142\">FINN: </strong>When the government imposed restrictions on the use of paper.</p>\n<p data-start=\"3213\" data-end=\"3354\"><strong data-start=\"3213\" data-end=\"3222\">MAYA: </strong>Yeah, but that was only in the UK. In the USA, programmes – or rather, playbills – continued to be published in the same format …</p>\n<p data-start=\"3356\" data-end=\"3723\"><strong data-start=\"3356\" data-end=\"3365\">FINN: </strong>… while here in the UK, programmes became merely a single sheet of paper folded to create four pages for text.</p>\n<p data-start=\"3356\" data-end=\"3723\"><strong data-start=\"3213\" data-end=\"3222\">MAYA: </strong>What I don’t really get is that, after the war, <span style=\"background-color: #f3db7b;\">they didn’t go back to being more than one sheet, or change in any way for over twenty-five years <strong data-start=\"3716\" data-end=\"3723\">Q26 </strong></span>. I know there were paper shortages after the war, but only for five or ten years.</p>\n<p data-start=\"3356\" data-end=\"3723\"><strong data-start=\"3356\" data-end=\"3365\">FINN: </strong>Strange. </p>\n<hr data-start=\"3725\" data-end=\"3728\">\n<p data-start=\"3730\" data-end=\"3831\"><strong data-start=\"3730\" data-end=\"3739\">MAYA: </strong>I’ve got some pictures of programmes we could include on the slides for our presentation.</p>\n<p data-start=\"3833\" data-end=\"3912\"><strong data-start=\"3833\" data-end=\"3842\">FINN: </strong>I found a couple too, Maya. Let’s go through and see what we think.</p>\n<p data-start=\"3914\" data-end=\"3981\"><strong data-start=\"3914\" data-end=\"3923\">MAYA: </strong>Erm … this is an old one, for a play called <em data-start=\"3970\" data-end=\"3980\">Ruy Blas</em>.</p>\n<p data-start=\"3983\" data-end=\"4056\"><strong data-start=\"3983\" data-end=\"3992\">FINN: </strong>Never heard of that, but the programme looks very decorative.</p>\n<p data-start=\"4058\" data-end=\"4176\"><strong data-start=\"4058\" data-end=\"4067\">MAYA: </strong><span style=\"background-color: #f3db7b;\">Good enough to put in a frame on the wall. <strong data-start=\"4169\" data-end=\"4176\">Q27</strong></span> The images are just beautiful. Finn, what did you find? </p>\n<p data-start=\"4178\" data-end=\"4499\"><strong data-start=\"4178\" data-end=\"4187\">FINN: </strong>I’ve got some pages from a programme for <em data-start=\"4231\" data-end=\"4249\">Man of La Mancha</em>. I thought this was a good programme to show, not because of the pictures, but because it contains articles written by members of the theatre company. <span style=\"background-color: #f3db7b;\">So we can learn how the production was created, and the thoughts and feelings of the cast. <strong data-start=\"4492\" data-end=\"4499\">Q28</strong></span></p>\n<p data-start=\"4501\" data-end=\"4728\"><strong data-start=\"4501\" data-end=\"4510\">MAYA: </strong>Good. I’ve got a copy of a programme that’s now in a museum. It’s for <em data-start=\"4583\" data-end=\"4610\">The Tragedy of Jane Shore</em> and it’s said to be<span style=\"background-color: #f3db7b;\"> the earliest surviving document to have been printed on Australia’s first printing press. <strong data-start=\"4721\" data-end=\"4728\">Q29</strong></span></p>\n<p data-start=\"4730\" data-end=\"4752\"><strong data-start=\"4730\" data-end=\"4739\">FINN: </strong>Fantastic.</p>\n<p data-start=\"4754\" data-end=\"5023\"><strong data-start=\"4754\" data-end=\"4763\">MAYA: </strong>OK. Another programme to talk about is for <em data-start=\"4809\" data-end=\"4832\">The Sailors’ Festival</em>. It comes from <span style=\"background-color: #f3db7b;\">the British Library’s digitised collection of programmes that was started a few years ago.<strong data-start=\"5016\" data-end=\"5023\">Q30</strong> </span>It already comprises over two hundred thousand programmes, which is amazing. </p>\n<p data-start=\"5025\" data-end=\"5091\" data-is-last-node=\"\" data-is-only-node=\"\"><strong data-start=\"5025\" data-end=\"5034\">FINN: </strong>Wish I’d known about it while I was doing my research!</p>"}]', 0);
INSERT INTO public.questions VALUES ('82d67841-6583-47b2-89cc-e0a406757689', '1793f174-7dcb-4b5a-aea5-f256f19b3302', 'matching', 'Questions 27–30', '', '<p data-start="96" data-end="173"><strong data-start="96" data-end="173">What comment is made about the programme for each of the following shows?</strong></p>
<p data-start="175" data-end="279">Choose <strong data-start="182" data-end="190">FOUR</strong> answers from the box and write the correct letter, <strong data-start="242" data-end="249">A–F</strong>, next to Questions <strong data-start="269" data-end="278">27–30</strong>.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><span style=\"font-size: 12pt;\"><strong>Show</strong></span></p>\n<p> </p>\n<p>Ruy Blas {It resembles an artwork.}</p>\n<p> </p>\n<p>Man of La Mancha  {It contains insights into the show.}</p>\n<p> </p>\n<p>The Tragedy of Jane Shore {It is historically significant for a country.}</p>\n<p> </p>\n<p>The Sailors’ Festival {It is included in a recent project.}</p>", "answerOptions": [{"optionText": "Its origin is somewhat controversial."}, {"optionText": "It is historically significant for a country."}, {"optionText": "It was effective at attracting audiences."}, {"optionText": "It is included in a recent project."}, {"optionText": "It contains insights into the show."}, {"optionText": "It resembles an artwork."}], "matchingItems": []}', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('59528ea7-af63-4527-8bb8-e37416dab229', '7206f915-13e6-4581-aedb-7f5f00d3750f', 'fillup', 'Questions 31–40', '<p>Write <strong data-start="138" data-end="155">ONE WORD ONLY</strong> for each answer</p>
<p style="text-align: left;" data-start="179" data-end="198"><strong><span style="font-size: 14pt;">Inclusive design</span></strong></p>
<p data-start="200" data-end="216"><strong>Definition</strong></p>
<p data-start="217" data-end="455">• Designing products that can be accessed by a diverse range of people without the need for any <strong data-start="313" data-end="327">{adaptation}</strong>.<br data-start="328" data-end="331">• Not the same as universal design: that is design for everyone, including catering for people with <strong data-start="431" data-end="445">{cognitive}</strong> problems.</p>
<p data-start="457" data-end="491"><strong>Examples of inclusive design</strong></p>
<p data-start="492" data-end="624">• <strong data-start="494" data-end="508">{desks}</strong> which are adjustable, avoiding back or neck problems<br data-start="561" data-end="564">• <strong data-start="566" data-end="580">{taps}</strong> in public toilets which are easier to use</p>
<p data-start="626" data-end="782">• To assist the elderly:<br data-start="650" data-end="653">– designers avoid using <strong data-start="677" data-end="691">{blue}</strong> in interfaces<br data-start="705" data-end="708">– people can make commands using a mouse, keyboard or their <strong data-start="768" data-end="782">{voice}</strong></p>
<p data-start="789" data-end="825"><strong>Impact of non-inclusive designs</strong></p>
<p data-start="827" data-end="839">Access</p>
<p data-start="840" data-end="883">– Loss of independence for disabled people.</p>
<p data-start="885" data-end="897">Safety</p>
<p data-start="898" data-end="1128">– Seatbelts are especially problematic for <strong data-start="941" data-end="955">{pregnant}</strong> women.<br data-start="962" data-end="965">– PPE jackets are often unsuitable because of the size of women’s <strong data-start="1031" data-end="1045">{shoulders}</strong>.<br data-start="1046" data-end="1049">– PPE for female <strong data-start="1066" data-end="1080">{police}</strong> officers dealing with emergencies is the worst.</p>
<p data-start="1130" data-end="1160">Comfort in the workplace</p>
<p data-start="1161" data-end="1220" data-is-last-node="" data-is-only-node="">– The <strong data-start="1167" data-end="1181">{temperature}</strong> in offices is often too low for women.</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-section-id=\"suogjp\" data-start=\"57\" data-end=\"67\">PART 4</h3>\n<p data-start=\"69\" data-end=\"503\">It’s only relatively recently that designers have become aware of the need to be inclusive when designing products. But what does that mean exactly? Well, it simply means designing products that span economic, social and cultural barriers. It means making sure products are accessible – so that as many different types of people as possible can use them without any type of <strong><span style=\"background-color: #f3db7b;\">adaptation </span><span style=\"background-color: #f3db7b;\">Q31</span><span style=\"background-color: #f3db7b;\"> </span></strong>having to be made to the original design. </p>\n<p data-start=\"505\" data-end=\"794\">Inclusive design is often linked with universal design, although they are not quite the same thing. Universal design aims to make products that work for everyone and that includes considering the needs of people who have <span style=\"background-color: #f3db7b;\"><strong>cognitive Q32 </strong></span>difficulties, which can present quite a challenge. </p>\n<p data-start=\"796\" data-end=\"1121\">Today, examples of successful inclusive design can be seen all around us. In workplaces it is common to see <span style=\"background-color: #f3db7b;\"><strong>desks Q33 </strong></span>which can be adjusted to suit people of different heights or for wheelchair users. This still isn’t always the case, however, and is one reason why office workers often suffer from back or neck problems. </p>\n<p data-start=\"1123\" data-end=\"1399\">You’ll find another example in the public toilets of countless hotels, airports and offices. <span style=\"background-color: #f3db7b;\"><strong>Taps Q34 </strong></span>that you activate by sensor require no pressing or twisting movements. These are not only more hygienic, they’re also easier for people with dexterity or mobility issues. </p>\n<p data-start=\"1406\" data-end=\"2076\">The tech industry has been criticised in the past for focusing too much on young consumers but this is changing. Many products are now designed with the elderly in mind. For example, it’s well known that vision declines with age, and that we also become worse at distinguishing between similar colours; in particular, shades of <span style=\"background-color: #f3db7b;\"><strong>blue </strong><strong data-start=\"2065\" data-end=\"2076\">Q35</strong></span>, which is why software designers rarely create interfaces with this colour. Motor skills also decline with age and some people have difficulty doing everyday things like picking up a cup or opening a door. This can also affect their ability to use a mouse or keyboard. So <span style=\"background-color: #f3db7b;\"><strong>voice Q36 </strong></span>access is now a routine way of making commands. </p>\n<hr>\n<p data-start=\"2083\" data-end=\"2520\">It’s worth looking at the problems non-inclusive designs cause when not enough consideration is given to a range of users, as it can have a serious impact on people’s lives. Access is one obvious example because it has such a huge impact on disabled people’s independence. Not being able to access public transport because buses or trains are not wheelchair-friendly means many disabled people can’t go out unless someone goes with them.</p>\n<p data-start=\"2522\" data-end=\"2800\">Safety is another issue. Inexplicably, most cars are still crash-tested using a dummy based on an average-sized male. This has safety implications for all women, particularly those who are <strong><span style=\"background-color: #f3db7b;\">pregnant </span><span style=\"background-color: #f3db7b;\">Q37</span></strong>, as the seatbelts worn by the dummy are not adapted to accommodate them. </p>\n<p data-start=\"2802\" data-end=\"3111\">Over the past 100 years, workplaces in the UK have, on the whole, become considerably safer. Employers are legally required to provide well-maintained personal protective equipment or PPE – anything from goggles to full body suits – to workers who need it, free of charge. But most PPE is designed to fit men.</p>\n<p data-start=\"3113\" data-end=\"3685\">A recent report found that employers often think that when it comes to female workers, all they need to do to comply with this legal requirement is to buy jackets, for example, designed for a small man. The problem with this is that women can be tall and still have much smaller <span style=\"background-color: #f3db7b;\"><strong>shoulders Q38 </strong></span>than the average man. Ill-fitting PPE such as hi-vis jackets, vests and body armour can put women at risk. The report found that 95% of women said that their PPE often hampered their work and that this problem was worse in the emergency services, particularly the <strong><span style=\"background-color: #f3db7b;\">police. Q39</span></strong></p>\n<p data-start=\"3687\" data-end=\"4309\">Another problem is related to comfort at work. A very common scenario in offices in summertime is to see women wrapped in blankets or wearing sweaters while the air conditioning is on high. Meanwhile the men are in shorts and T-shirts. This is due to differences in metabolic rates for men and women. There is a standard setting for air conditioning to be at a <span style=\"background-color: #f3db7b;\"><strong>temperature Q40 </strong></span>of 21 degrees, designed to suit men, and in most modern offices it’s not possible to turn the air conditioning up or down. This means that many offices which mainly employ women are wasting energy by having the air conditioning set too high. </p>"}]', 0);
INSERT INTO public.questions VALUES ('1cb5ded9-10ec-4f56-ab89-2eaf1ebb5f0f', '396fdc93-9f96-466a-825c-dd4e4e8fca75', 'matrix', 'Questions 16-20', NULL, '<p class="section-instructions">Label the map below.<br />Write the correct letter, <strong>A-H</strong>, next to questions 16-20.</p>
<h3 style="text-align: left;">Clifton Bird Park</h3>
<p><img decoding="async" style="float: left;" src="data:image/png;base64," width="406" height="366" loading="lazy"></p>
', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "Wooden bridge", "correctCategoryLetter": "F"}, {"itemText": "Observation tower ", "correctCategoryLetter": "H"}, {"itemText": "Visitor cabins", "correctCategoryLetter": "C"}, {"itemText": "Nesting boxes ", "correctCategoryLetter": "E"}, {"itemText": "Boat sheds", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('027a65f9-df98-4aa0-8189-6a7571d5c3f1', 'cd48a8aa-43cb-49d6-977b-9e26b1dc866e', 'radio', 'Questions 11-15', NULL, '<p>Choose the correct answers</p>
<p><strong>Working at Parson’s Fruit Farm</strong></p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "The backpackers'' hostel is full."}, {"content": "The motel is close to the farm."}, {"content": "The campground is cheap."}], "question": "What does the manager say about accommodation?"}, {"correct": 2, "options": [{"content": "perfect for growing fruit."}, {"content": "worse than last year."}, {"content": "hard to predict accurately."}], "question": "The weather this summer has been"}, {"correct": 0, "options": [{"content": "require an appropriate licence."}, {"content": "need previous orchard experience."}, {"content": "must be over 18 years old."}], "question": "The manager says that tractor drivers"}, {"correct": 1, "options": [{"content": "may be rather hot."}, {"content": "can be noisy at times."}, {"content": "will often be dirty."}], "question": "Working inside the shed"}, {"correct": 0, "options": [{"content": "Eat and drink regularly."}, {"content": "Try not to damage the trees."}, {"content": "Leave your phones in a secure location."}], "question": "What final advice does the manager give?"}]', 'null', 'null', 'null', '[{"content": "<h2 class=\"\" data-path-to-node=\"2\">PART 2</h2>\n<p data-path-to-node=\"3\"><strong class=\"\" data-path-to-node=\"3\" data-index-in-node=\"0\">Manager:</strong><span class=\"\"> Well hello everyone and welcome to Parsons Fruit Farm.</span><span class=\"\"> It’s good to see a mix of so many different nationalities who have all come here on their working holidays.</span><span class=\"\"> I’m sure you’re gonna enjoy working on our farm.</span></p>\n<p data-path-to-node=\"4\"><span class=\"\">First of all,</span><span class=\"\"> just a few words about accommodation.</span><span class=\"\"> I know that some of you have pitched your tents down at the campground but are looking for something more comfortable.</span><span class=\"\"> So one option is the motel.</span><span class=\"\"> It’s </span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"4\" data-index-in-node=\"204\">(11) located very conveniently just a few minutes away (B: close to the farm)</strong></span><span class=\"\"> and they often do reduced rates if you’re staying long term.</span><span class=\"\"> And then the Backpackers Hostel is always very popular,</span><span class=\"\"> though it can be busy at this time of year.</span></p>\n<p data-path-to-node=\"5\"><span class=\"\">Okay,</span><span class=\"\"> so the work itself.</span><span class=\"\"> This summer the weather’s been pretty mixed.</span><span class=\"\"> We’ve had a bit of everything and </span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"5\" data-index-in-node=\"105\">(12) the forecasts have always been wrong (C: hard to predict accurately)</strong><span class=\"\">.</span></span><span class=\"\"> So some of the apples and pears aren’t in great condition.</span><span class=\"\"> That said,</span><span class=\"\"> this season’s been better than some we’ve had recently and the autumn looks like it’s gonna be great,</span><span class=\"\"> so we should have ideal conditions for the harvest.</span></p>\n<p data-path-to-node=\"6\"><span class=\"\">So there are a number of different jobs to do.</span><span class=\"\"> Most of you will be fruit picking.</span><span class=\"\"> We’ll give all the fruit pickers gloves to wear to protect your fingers so you won’t hurt yourselves.</span><span class=\"\"> We’ll also be looking for some tractor drivers.</span><span class=\"\"> Their job is to collect the full baskets of fruit and take them to the shed.</span><span class=\"\"> I should say in this country,</span><span class=\"\"> anyone is allowed to drive a tractor on farmland once they’re 13 rather than 18 as in some countries.</span><span class=\"\"> However,</span><span class=\"\"> we do have certain rules that are specific to our farm.</span><span class=\"\"> You don’t need to have done farm work before,</span><span class=\"\"> but here you </span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"6\" data-index-in-node=\"565\">(13) must have a relevant document or permit from your country (A: require an appropriate license)</strong></span><span class=\"\"> that allows you to operate this type of vehicle.</span></p>\n<p data-path-to-node=\"7\"><span class=\"\">Then there are also lots of jobs working inside the shed.</span><span class=\"\"> This involves sorting the fruit and cleaning it if necessary.</span><span class=\"\"> There’s a lot of heavy machinery in the shed,</span><span class=\"\"> so </span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"7\" data-index-in-node=\"169\">(14) when that’s operating, you must wear your ear protection (B: can be noisy)</strong></span><span class=\"\">.</span><span class=\"\"> The big advantage is the shed’s fully air conditioned,</span><span class=\"\"> so it’s a pleasant environment regardless of what the weather’s doing outside.</span></p>\n<p data-path-to-node=\"8\"><span class=\"\">Alright well,</span><span class=\"\"> whatever job you do,</span><span class=\"\"> I’ll just give you some final advice.</span><span class=\"\"> When you’re picking the fruit,</span><span class=\"\"> sometimes you can break off a small branch—that’s not something you need to be worried about,</span><span class=\"\"> it’ll grow back.</span><span class=\"\"> Also </span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"8\" data-index-in-node=\"220\">(15) remember to have snacks and use your water bottles (A: eat and drink regularly)</strong></span><span class=\"\">; often people get exhausted quickly during harvest time.</span><span class=\"\"> And if you’ve got a mobile or cell,</span><span class=\"\"> keep it with you at all times in case there’s an emergency.</span></p>\n<hr class=\"\" data-path-to-node=\"9\" />\n<p data-path-to-node=\"10\"><strong class=\"\" data-path-to-node=\"10\" data-index-in-node=\"0\">Manager:</strong><span class=\"\"> Alright,</span><span class=\"\"> I’d like to quickly go over where everything is located.</span><span class=\"\"> So look at your maps of Parsons Fruit Farm and find the main yard.</span><span class=\"\"> It’s towards the bottom of your maps—that really is the center of the farm.</span></p>\n<p data-path-to-node=\"11\"><span class=\"\">Okay,</span><span class=\"\"> the first place I’ll mention is the </span><strong class=\"\" data-path-to-node=\"11\" data-index-in-node=\"42\">workshop</strong><span class=\"\">.</span><span class=\"\"> This is close to the main yard,</span><span class=\"\"> but you actually have to leave the yard to get into it.</span><span class=\"\"> So you need to take the road that goes out to the orchards and you </span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"11\" data-index-in-node=\"207\">access the workshop from there (16: G)</strong><span class=\"\">.</span></span></p>\n<p data-path-to-node=\"12\"><span class=\"\">Then the </span><strong class=\"\" data-path-to-node=\"12\" data-index-in-node=\"9\">lunchroom</strong><span class=\"\">.</span><span class=\"\"> On the north side of the map,</span><span class=\"\"> there’s a road that curves sharply round to the left.</span> <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"12\" data-index-in-node=\"104\">Halfway around this bend (17: B)</strong><span class=\"\">,</span></span><span class=\"\"> you’ll find the entrance to the lunchroom.</span><span class=\"\"> It’s a pretty place next to the river and also beside a little wood.</span></p>\n<p data-path-to-node=\"13\"><span class=\"\">You also need to be able to find the </span><strong class=\"\" data-path-to-node=\"13\" data-index-in-node=\"37\">farm office</strong><span class=\"\">.</span><span class=\"\"> So if you look at the main yard,</span><span class=\"\"> you’ll see there’s a number of different buildings located around it,</span><span class=\"\"> and the farm office is the </span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"13\" data-index-in-node=\"180\">smallest one on the south side (18: H)</strong><span class=\"\">.</span></span></p>\n<p data-path-to-node=\"14\"><span class=\"\">Obviously the </span><strong class=\"\" data-path-to-node=\"14\" data-index-in-node=\"14\">first aid room</strong><span class=\"\"> is important.</span><span class=\"\"> Now this is close to the main yard so it’s quick to get there,</span><span class=\"\"> and it’s actually more or less in the middle of your maps.</span><span class=\"\"> That </span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"14\" data-index-in-node=\"170\">little building that’s attached to the farmhouse (19: F)</strong><span class=\"\">.</span></span></p>\n<p data-path-to-node=\"15\"><span class=\"\">Then the </span><strong class=\"\" data-path-to-node=\"15\" data-index-in-node=\"9\">store shed</strong><span class=\"\">.</span><span class=\"\"> From the main yard,</span><span class=\"\"> take the road heading north.</span><span class=\"\"> Go past the farmhouse and turn right.</span><span class=\"\"> <span style=\"text-decoration: underline; background-color: #ffe786;\">The </span></span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong class=\"\" data-path-to-node=\"15\" data-index-in-node=\"112\">store is down that road (20: D)</strong><span class=\"\">.</span></span><span class=\"\"> If you come to the vegetable gardens,</span><span class=\"\"> you’ve gone too far.</span></p>\n<p data-path-to-node=\"16\"><span class=\"\">Now the other thing is…</span></p>\n"}]', 0);
INSERT INTO public.questions VALUES ('1a456919-a441-4829-8a3e-f0946592fc14', '579e7bb5-8e5a-4884-9d12-abd9b7d3baac', 'matching', 'Questions 11–16', '', '<p data-start="123" data-end="198">What is the role of the volunteers in each of the following activities?</p>
<p data-start="200" data-end="295">Choose <strong>SIX </strong>answers from the box and write the correct letter, <strong data-start="262" data-end="269">A–I</strong>, next to Questions 11–16.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><span style=\"font-size: 12pt;\"><strong>Activities</strong></span></p>\n<p> </p>\n<p><span style=\"font-size: 12pt;\">walking around the town centre {giving advice to visitors}</span></p>\n<p> </p>\n<p><span style=\"font-size: 12pt;\">helping at concerts {helping people find their seats}</span></p>\n<p> </p>\n<p><span style=\"font-size: 12pt;\">getting involved with community groups {encouraging cooperation between local organisations}</span></p>\n<p> </p>\n<p><span style=\"font-size: 12pt;\">helping with a magazine {collecting feedback on events}</span></p>\n<p> </p>\n<p><span style=\"font-size: 12pt;\">participating at lunches for retired people {providing entertainment}</span></p>\n<p> </p>\n<p><span style=\"font-size: 12pt;\">helping with the website {providing publicity about a council service}</span></p>", "answerOptions": [{"optionText": "providing entertainment"}, {"optionText": "providing publicity about a council service"}, {"optionText": "contacting local businesses"}, {"optionText": "giving advice to visitors"}, {"optionText": "collecting feedback on events"}, {"optionText": "selling tickets"}, {"optionText": "introducing guest speakers at an event"}, {"optionText": "encouraging cooperation between local organisations"}, {"optionText": "helping people find their seats"}], "matchingItems": []}', 'null', '[{"content": "<p data-section-id=\"1o6viqo\" data-start=\"70\" data-end=\"83\"><strong data-start=\"73\" data-end=\"83\">PART 2</strong></p>\n<p data-start=\"85\" data-end=\"438\">Good morning everyone. I’m Steve Wainwright, from Elmleigh Town Council, and I organise the town’s volunteer scheme. I’m delighted you’re all interested in joining the scheme. Our volunteers help to create a sense of community among the many people who live in our historic town of Elmleigh, and make residents and visitors feel welcome at local events.</p>\n<p data-start=\"440\" data-end=\"716\">First I’ll mention just a few of the activities that volunteers carry out. One is to walk around the town centre streets wearing our volunteer T-shirt. Tourists often ask how to get to a particular shop, and <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong>(11) </strong><strong>they might also be grateful for recommendations</strong></span> about what to visit.</p>\n<p data-start=\"718\" data-end=\"996\">The town holds a large number of concerts each year, and part of the volunteers’ role is to <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong>(12) get everyone in the audience to the right place</strong></span> as smoothly as possible. You’d be surprised how many people buy tickets then don’t check them, and head for the wrong section of the hall!</p>\n<p data-start=\"998\" data-end=\"1335\">Volunteers may get involved with community groups, such as sports clubs or gardeners’ associations. Here the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong>(13) volunteers talk about how groups can help each other</strong></span>. For instance, a writing group might want to travel to another town to hear a talk by a well-known author, but may not know that another club has a coach they could travel in.</p>\n<hr data-start=\"1337\" data-end=\"1340\">\n<p data-start=\"1342\" data-end=\"1751\">The town produces a monthly magazine, and anyone who lives in the town can send in articles. It’s free to residents, and is paid for by local businesses – that’s the responsibility of the council’s advertising department. We depend on volunteers, though, <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong>(14) to find out what people think of events they’ve attended, and any suggestions they have</strong></span> for the future. The volunteers then send a summary to the editors.</p>\n<p data-start=\"1753\" data-end=\"2133\">There are a number of clubs for retired people, and every year, the council arranges lunch for all the members. The volunteers welcome the guests, and when everyone’s sitting down and relaxing after the meal, <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong>(15) some volunteers put on a show</strong></span> – usually around half an hour of songs and short plays. The club members really welcome the chance to chat to the volunteers at these events.</p>\n<p data-start=\"2135\" data-end=\"2365\">The town council has a website, of course, and <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong>(16) volunteers are asked to help by making sure residents know about it</strong></span>. It’s updated every day with information about future activities, and we want as many people as possible to use it.</p>\n<hr data-start=\"2367\" data-end=\"2370\">\n<p data-start=\"2372\" data-end=\"2889\">OK, now you know some of the things our volunteers do, I’ll go on to some practical matters. As you probably know, the town arranges three major festivals every year, and they all depend on a large number of volunteers. The book festival lasts three days, and uses several venues, which all need volunteers. More are needed for the music festival, because that lasts a whole week, and <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong>(17) even more help is required for the science festival</strong></span>, even though it’s only two days long. It involves quite a lot of venues, though.</p>\n<p data-start=\"2891\" data-end=\"3398\">It’s a good idea to help at the festival you’re most interested in, because you can attend most of the events for free. We try to use volunteers who are flexible, though, because some festival events are held outdoors, and the weather may affect the size of the audience, and even whether the event can take place, so there can be changes at short notice. <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong>(18) What’s essential, though, is being able to get on well with other people</strong></span>, and also to deal with someone who’s behaving badly – as occasionally happens.</p>\n<hr data-start=\"3400\" data-end=\"3403\">\n<p data-start=\"3405\" data-end=\"3739\">Our plan is to get you all working in September, after a week’s training starting on the 2nd. So we’ll be timetabling you for duties the following week, <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong>(19) from the 9th onward</strong></span>. Later, in the week beginning September 23rd, we have a chat with each of you, to find out how you feel about being a volunteer, and what extra support you need.</p>\n<p data-start=\"3741\" data-end=\"4079\">As a thank you to the volunteers, we arrange an annual event. In recent years we’ve had a party in the town hall, and last year a barbecue in Chamber Park. Our forthcoming event is a <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong>(20) trip along the canal</strong></span> from here to Dewhurst and back. It’s on Saturday September the 28th, and if you’d like to attend, you can sign up once you start work.</p>\n<p data-start=\"4081\" data-end=\"4118\">Now this is the volunteers’ T-shirt …</p>"}]', 0);
INSERT INTO public.questions VALUES ('47e74750-b9b6-440f-9908-4fbab5146a55', '579e7bb5-8e5a-4884-9d12-abd9b7d3baac', 'radio', 'Questions 17–20', '', '<p>Choose the correct letter, <strong>A</strong>, <strong>B </strong>or <strong>C</strong>.</p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "A. the music festival"}, {"option_text": "B. the science festival"}, {"option_text": "C. the book festival"}], "question": "Which event requires the largest number of volunteers?"}, {"correct": 0, "options": [{"option_text": "A. interpersonal skills"}, {"option_text": "B. personal interest in the event"}, {"option_text": "C. flexibility"}], "question": "What is the most important requirement for volunteers at the festivals?"}, {"correct": 1, "options": [{"option_text": "A. 2 September"}, {"option_text": "B. 9 September"}, {"option_text": "C. 23 September"}], "question": "New volunteers will start working in the week beginning"}, {"correct": 0, "options": [{"option_text": "A. a boat trip"}, {"option_text": "B. a barbecue"}, {"option_text": "C. a party"}], "question": "What is the next annual event for volunteers?"}]', 'null', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('bb2e6f13-8d9b-4ea3-b625-a7c78b265b9c', 'bcb6dad3-ac11-4098-b8c0-3f1d5808f6b0', 'matching', 'Questions 21–25', '', '<p data-start="131" data-end="220">What is Rosie and Colin’s opinion about each of the following aspects of human geography?</p>
<p data-start="222" data-end="322">Choose <strong data-start="229" data-end="237">FIVE</strong> answers from the box and write the correct letter, <strong data-start="289" data-end="296">A–G</strong>, next to Questions 21–25.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><span style=\"font-size: 12pt;\"><strong>Aspects of human geography</strong></span></p>\n<p> </p>\n<p><span style=\"font-size: 12pt;\">Population {It will be easy to find facts about this.}</span></p>\n<p> </p>\n<p><span style=\"font-size: 12pt;\">Health {The information provided about this was interesting}</span></p>\n<p> </p>\n<p><span style=\"font-size: 12pt;\">Economies {This may not be relevant to their course.}</span></p>\n<p> </p>\n<p><span style=\"font-size: 12pt;\">Culture {The information given about this was too vague.}</span></p>\n<p> </p>\n<p><span style=\"font-size: 12pt;\">Poverty {The facts about this may not be reliable.}</span></p>", "answerOptions": [{"optionText": "The information given about this was too vague."}, {"optionText": "This may not be relevant to their course."}, {"optionText": "This will involve only a small number of statistics."}, {"optionText": "It will be easy to find facts about this."}, {"optionText": "The facts about this may not be reliable."}, {"optionText": "No useful research has been done on this."}, {"optionText": "The information provided about this was interesting"}], "matchingItems": []}', 'null', '[{"content": "<p data-section-id=\"1o6vl7l\" data-start=\"76\" data-end=\"89\"><strong data-start=\"79\" data-end=\"89\">PART 3</strong></p>\n<p data-start=\"91\" data-end=\"188\"><strong data-start=\"91\" data-end=\"101\">ROSIE:</strong><br data-start=\"101\" data-end=\"104\">Colin, I’m really struggling to think of a topic for our human geography assignment.</p>\n<p data-start=\"190\" data-end=\"362\"><strong data-start=\"190\" data-end=\"200\">COLIN:</strong><br data-start=\"200\" data-end=\"203\">Me too, Rosie. I’ll tell you what, let’s think about the different aspects of human geography, and see if we can narrow the topic down a bit to help us decide.</p>\n<p data-start=\"364\" data-end=\"528\"><strong data-start=\"364\" data-end=\"374\">ROSIE:</strong><br data-start=\"374\" data-end=\"377\">OK, so one aspect is population. That would be all about population density and migration and so on. Lots of facts and statistics … Maybe a bit boring?</p>\n<p data-start=\"530\" data-end=\"599\"><strong data-start=\"530\" data-end=\"540\">COLIN:</strong><br data-start=\"540\" data-end=\"543\">Yeah, but <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong>(21) quite straightforward to find on the internet</strong></span>.</p>\n<hr data-start=\"601\" data-end=\"604\">\n<p data-start=\"606\" data-end=\"884\"><strong data-start=\"606\" data-end=\"616\">ROSIE:</strong><br data-start=\"616\" data-end=\"619\">Suppose so. How about health? I’d never thought about the links between that and geography until Professor Lee gave us that lecture on cholera. How in the nineteenth century a physician used maps and plans of water supplies to find the source of a cholera epidemic.</p>\n<p data-start=\"886\" data-end=\"984\"><strong data-start=\"886\" data-end=\"896\">COLIN:</strong><br data-start=\"896\" data-end=\"899\">Yes – <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong>(22) fascinating, wasn’t it</strong></span>? Or we could do something more general – like economies.</p>\n<p data-start=\"986\" data-end=\"1078\"><strong data-start=\"986\" data-end=\"996\">ROSIE:</strong><br data-start=\"996\" data-end=\"999\">So how financial and commercial factors are linked to the physical environment?</p>\n<p data-start=\"1080\" data-end=\"1098\"><strong data-start=\"1080\" data-end=\"1090\">COLIN:</strong><br data-start=\"1090\" data-end=\"1093\">Yeah.</p>\n<p data-start=\"1100\" data-end=\"1174\"><strong data-start=\"1100\" data-end=\"1110\">ROSIE:</strong><br data-start=\"1110\" data-end=\"1113\"><span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong>(23) I thought that had been taken off the syllabus for this year</strong></span>.</p>\n<p data-start=\"1176\" data-end=\"1196\"><strong data-start=\"1176\" data-end=\"1186\">COLIN:</strong><br data-start=\"1186\" data-end=\"1189\">Has it?</p>\n<p data-start=\"1198\" data-end=\"1258\"><strong data-start=\"1198\" data-end=\"1208\">ROSIE:</strong><br data-start=\"1208\" data-end=\"1211\">I’m not sure. But it might be best to avoid it.</p>\n<hr data-start=\"1260\" data-end=\"1263\">\n<p data-start=\"1265\" data-end=\"1380\"><strong data-start=\"1265\" data-end=\"1275\">COLIN:</strong><br data-start=\"1275\" data-end=\"1278\">OK. Maybe we could do something on culture. We had that lecture about culture and geography last week.</p>\n<p data-start=\"1382\" data-end=\"1493\"><strong data-start=\"1382\" data-end=\"1392\">ROSIE:</strong><br data-start=\"1392\" data-end=\"1395\">I didn’t get much out of that. <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong>(24) It was so general and the lecturer didn’t give any useful examples</strong></span>.</p>\n<p data-start=\"1495\" data-end=\"1563\"><strong data-start=\"1495\" data-end=\"1505\">COLIN:</strong><br data-start=\"1505\" data-end=\"1508\">Yeah, I hardly took any notes, it didn’t seem worth it.</p>\n<hr data-start=\"1565\" data-end=\"1568\">\n<p data-start=\"1570\" data-end=\"1594\"><strong data-start=\"1570\" data-end=\"1580\">ROSIE:</strong><br data-start=\"1580\" data-end=\"1583\">We neither.</p>\n<p data-start=\"1596\" data-end=\"1678\"><strong data-start=\"1596\" data-end=\"1606\">COLIN:</strong><br data-start=\"1606\" data-end=\"1609\">We could focus on poverty. That’s something that’s a global problem …</p>\n<p data-start=\"1680\" data-end=\"1845\"><strong data-start=\"1680\" data-end=\"1690\">ROSIE:</strong><br data-start=\"1690\" data-end=\"1693\">The trouble is, Dr Lee was saying that <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong>(25) you have to be careful with some of the figures relating to poverty – they’re sometimes deliberately manipulated</strong></span>.</p>\n<p data-start=\"1847\" data-end=\"1920\"><strong data-start=\"1847\" data-end=\"1857\">COLIN:</strong><br data-start=\"1857\" data-end=\"1860\">You mean the information gets changed for political reasons?</p>\n<p data-start=\"1922\" data-end=\"1959\"><strong data-start=\"1922\" data-end=\"1932\">ROSIE:</strong><br data-start=\"1932\" data-end=\"1935\">That sort of thing, yes.</p>\n<hr data-start=\"1961\" data-end=\"1964\">\n<p data-start=\"1966\" data-end=\"2190\"><strong data-start=\"1966\" data-end=\"1976\">ROSIE:</strong><br data-start=\"1976\" data-end=\"1979\">So what are we going to do our assignment on? I’ll tell you what, one of the possibilities we haven’t discussed is urbanisation. And now over half the world’s population lives in cities, that’s really important.</p>\n<p data-start=\"2192\" data-end=\"2241\"><strong data-start=\"2192\" data-end=\"2202\">COLIN:</strong><br data-start=\"2202\" data-end=\"2205\">OK, good idea, Rosie. Let’s do that.</p>\n<p data-start=\"2243\" data-end=\"2318\"><strong data-start=\"2243\" data-end=\"2253\">ROSIE:</strong><br data-start=\"2253\" data-end=\"2256\">I love living in a big city, but of course there are problems.</p>\n<p data-start=\"2320\" data-end=\"2363\"><strong data-start=\"2320\" data-end=\"2330\">COLIN:</strong><br data-start=\"2330\" data-end=\"2333\">Things like theft and robbery?</p>\n<p data-start=\"2365\" data-end=\"2634\"><strong data-start=\"2365\" data-end=\"2375\">ROSIE:</strong><br data-start=\"2375\" data-end=\"2378\">Yes, but where I come from, that’s linked <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong>(26) to another more serious issue, which is that a lot of people don’t have jobs</strong></span>. That’s getting worse and worse. And we also still have quite a lot of people who are homeless, though that’s not quite so bad as it was.</p>\n<hr data-start=\"2636\" data-end=\"2639\">\n<p data-start=\"2641\" data-end=\"2770\"><strong data-start=\"2641\" data-end=\"2651\">COLIN:</strong><br data-start=\"2651\" data-end=\"2654\">It’d be nice to talk about some positive developments. Like some of the new developments on the outskirts of cities.</p>\n<p data-start=\"2772\" data-end=\"2856\"><strong data-start=\"2772\" data-end=\"2782\">ROSIE:</strong><br data-start=\"2782\" data-end=\"2785\">Yeah. They’ve opened some massive new shopping centres outside my city.</p>\n<p data-start=\"2858\" data-end=\"3101\"><strong data-start=\"2858\" data-end=\"2868\">COLIN:</strong><br data-start=\"2868\" data-end=\"2871\">Yeah, the same with mine – but it’s meant a lot of the shops in the city centre are closing down. But the outskirts are <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong>(27) ideal for building things that need a lot of space, like for conferences. They’ve opened a couple of big ones.</strong></span></p>\n<p data-start=\"3103\" data-end=\"3247\"><strong data-start=\"3103\" data-end=\"3113\">ROSIE:</strong><br data-start=\"3113\" data-end=\"3116\">Yes, we’ve got some too. It’d be nicer to have more facilities for things like football too. But that’s not happening where I live.</p>\n<p data-start=\"3249\" data-end=\"3278\"><strong data-start=\"3249\" data-end=\"3259\">COLIN:</strong><br data-start=\"3259\" data-end=\"3262\">Same in my area.</p>\n<hr data-start=\"3280\" data-end=\"3283\">\n<p data-start=\"3285\" data-end=\"3456\"><strong data-start=\"3285\" data-end=\"3295\">ROSIE:</strong><br data-start=\"3295\" data-end=\"3298\">We could include something about developing disused industrial sites. It seems like a good idea, because you’re not doing any harm to the natural environment.</p>\n<p data-start=\"3458\" data-end=\"3530\"><strong data-start=\"3458\" data-end=\"3468\">COLIN:</strong><br data-start=\"3468\" data-end=\"3471\">Yeah, but aren’t the buildings architecturally significant?</p>\n<p data-start=\"3532\" data-end=\"3735\"><strong data-start=\"3532\" data-end=\"3542\">ROSIE:</strong><br data-start=\"3542\" data-end=\"3545\">Not really. And what people forget is that they often used quite dangerous materials – chemicals and things – which haven’t been properly cleared away, so the whole site has to be made safe.</p>\n<p data-start=\"3737\" data-end=\"3813\"><strong data-start=\"3737\" data-end=\"3747\">COLIN:</strong><br data-start=\"3747\" data-end=\"3750\">Mm. <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong>(28) That can’t be cheap. And I bet it’s often not budgeted for</strong></span>.</p>\n<p data-start=\"3815\" data-end=\"3841\"><strong data-start=\"3815\" data-end=\"3825\">ROSIE:</strong><br data-start=\"3825\" data-end=\"3828\">You’re right.</p>\n<hr data-start=\"3843\" data-end=\"3846\">\n<p data-start=\"3848\" data-end=\"3893\"><strong data-start=\"3848\" data-end=\"3858\">COLIN:</strong><br data-start=\"3858\" data-end=\"3861\">Have you read about Masdar City?</p>\n<p data-start=\"3895\" data-end=\"4066\"><strong data-start=\"3895\" data-end=\"3905\">ROSIE:</strong><br data-start=\"3905\" data-end=\"3908\">In Abu Dhabi? Yes, it was designed to be a green city, wasn’t it? <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong>(29) That might be a good example of a city which set out to depend entirely on renewable energy.</strong></span></p>\n<p data-start=\"4068\" data-end=\"4196\"><strong data-start=\"4068\" data-end=\"4078\">COLIN:</strong><br data-start=\"4078\" data-end=\"4081\">Yes, we should say something about that. It was designed to be totally pedestrianised too, wasn’t it, with no cars.</p>\n<p data-start=\"4198\" data-end=\"4346\"><strong data-start=\"4198\" data-end=\"4208\">ROSIE:</strong><br data-start=\"4208\" data-end=\"4211\">Yes, and they had big plans for recycling to reduce waste to the lowest possible level. But let’s stick to talking about power sources.</p>\n<p data-start=\"4348\" data-end=\"4625\"><strong data-start=\"4348\" data-end=\"4358\">COLIN:</strong><br data-start=\"4358\" data-end=\"4361\">Then there’s that ecotown in England, Greenhill Abbots. It set out to conform to the usual principles – sustainability and so on. A lot of people were against it at first; they said the plans were unrealistic. <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong>(30) I’m not sure how far they’ve got with it – I’ll check</strong></span>.</p>\n<p data-start=\"4627\" data-end=\"4663\"><strong data-start=\"4627\" data-end=\"4637\">ROSIE:</strong><br data-start=\"4637\" data-end=\"4640\">Right. So it looks as …</p>"}]', 0);
INSERT INTO public.questions VALUES ('0e209ccf-e4da-49fc-aee2-0ad82f10f266', 'bcb6dad3-ac11-4098-b8c0-3f1d5808f6b0', 'radio', 'Questions 26–30', '', '<p>Choose the correct letter, <strong data-start="109" data-end="122">A, B or C</strong>.</p>', 'multiple_choice', '[{"correct": 2, "options": [{"option_text": "A. crime"}, {"option_text": "B. housing"}, {"option_text": "C. unemployment"}], "question": "Rosie says that in her own city the main problem is"}, {"correct": 0, "options": [{"option_text": "A. conference centres"}, {"option_text": "B. sports centres"}, {"option_text": "C. retail centres"}], "question": "What recent additions to the outskirts of their cities are both students happy about?"}, {"correct": 0, "options": [{"option_text": "A. have unexpected costs"}, {"option_text": "B. damage the urban environment"}, {"option_text": "C. destroy valuable historical buildings"}], "question": "The students agree that developing disused industrial sites may"}, {"correct": 1, "options": [{"option_text": "A. daily collections for waste recycling"}, {"option_text": "B. sustainable energy use"}, {"option_text": "C. free transport for everyone"}], "question": "The students will mention Masdar City as an example of an attempt to achieve"}, {"correct": 2, "options": [{"option_text": "A. what its objectives were"}, {"option_text": "B. why there was opposition to it"}, {"option_text": "C. how much of it has actually been built"}], "question": "When discussing the ecotown of Greenhill Abbots, Colin is uncertain about"}]', 'null', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('7990f709-b474-44a7-a88a-4602021bac98', 'af935e2f-33ab-4453-9d77-f453b5f73c94', 'fillup', 'Questions 22–26', '<p>Complete the summary. Write <strong>ONE WORD ONLY</strong> from the text for each answer.</p>
<p style="text-align: center;"><strong>Family-friendly practices at Plastic Solutions and the Margaret Mills Corporation</strong></p>
<p>At Plastic Solutions, a bi-weekly update is issued to workers at the same time as their pay. This includes a section dealing with problems such as {gossip} in communal areas of the workplace. The CEO also arranges a regular {seminar} for selected employees for workplace skills which are in great demand. Finally, employees’ families are invited to company open days, when they are allowed to try out the {machines}.</p>
<p>The Margaret Mills Corporation allows employees a degree of flexibility with their children, who can be brought to the office once {school} has finished. Mills likes to reward employees for company performance with a party or even a {trip} for families. There is considerable evidence that these practices are having the desired effect.<br> </p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-start=\"3064\" data-end=\"3081\"><strong data-start=\"3067\" data-end=\"3081\">22. gossip</strong></p>\n<p data-start=\"3083\" data-end=\"3104\"><strong data-start=\"3083\" data-end=\"3094\">Vị trí:</strong> Đoạn B.</p>\n<p data-start=\"3106\" data-end=\"3159\"><strong data-start=\"3106\" data-end=\"3120\">Dẫn chứng:</strong><br data-start=\"3120\" data-end=\"3123\">“This addresses issues like gossip…”</p>\n<p data-start=\"3161\" data-end=\"3234\"><strong data-start=\"3161\" data-end=\"3176\">Giải thích:</strong><br data-start=\"3176\" data-end=\"3179\">Phần coaching đề cập đến vấn đề gossip ở khu vực chung.</p>\n<p data-start=\"3241\" data-end=\"3259\"><strong data-start=\"3244\" data-end=\"3259\">23. seminar</strong></p>\n<p data-start=\"3261\" data-end=\"3282\"><strong data-start=\"3261\" data-end=\"3272\">Vị trí:</strong> Đoạn B.</p>\n<p data-start=\"3284\" data-end=\"3356\"><strong data-start=\"3284\" data-end=\"3298\">Dẫn chứng:</strong><br data-start=\"3298\" data-end=\"3301\">“…monthly invitation-only Business Pragmatics seminar…”</p>\n<p data-start=\"3358\" data-end=\"3421\"><strong data-start=\"3358\" data-end=\"3373\">Giải thích:</strong><br data-start=\"3373\" data-end=\"3376\">CEO tổ chức seminar hàng tháng cho nhân viên.</p>\n<p data-start=\"3428\" data-end=\"3447\"><strong data-start=\"3431\" data-end=\"3447\">24. machines</strong></p>\n<p data-start=\"3449\" data-end=\"3470\"><strong data-start=\"3449\" data-end=\"3460\">Vị trí:</strong> Đoạn B.</p>\n<p data-start=\"3472\" data-end=\"3540\"><strong data-start=\"3472\" data-end=\"3486\">Dẫn chứng:</strong><br data-start=\"3486\" data-end=\"3489\">“…kids can experiment with the company’s machines…”</p>\n<p data-start=\"3542\" data-end=\"3632\"><strong data-start=\"3542\" data-end=\"3557\">Giải thích:</strong><br data-start=\"3557\" data-end=\"3560\">Gia đình nhân viên có thể thử máy móc của công ty trong ngày Open House.</p>\n<p data-start=\"3639\" data-end=\"3656\"><strong data-start=\"3642\" data-end=\"3656\">25. school</strong></p>\n<p data-start=\"3658\" data-end=\"3679\"><strong data-start=\"3658\" data-end=\"3669\">Vị trí:</strong> Đoạn C.</p>\n<p data-start=\"3681\" data-end=\"3753\"><strong data-start=\"3681\" data-end=\"3695\">Dẫn chứng:</strong><br data-start=\"3695\" data-end=\"3698\">“…have their children dropped off when school is over…”</p>\n<p data-start=\"3755\" data-end=\"3832\"><strong data-start=\"3755\" data-end=\"3770\">Giải thích:</strong><br data-start=\"3770\" data-end=\"3773\">Trẻ em có thể được đưa đến công ty sau khi school kết thúc.</p>\n<p data-start=\"3839\" data-end=\"3854\"><strong data-start=\"3842\" data-end=\"3854\">26. trip</strong></p>\n<p data-start=\"3856\" data-end=\"3877\"><strong data-start=\"3856\" data-end=\"3867\">Vị trí:</strong> Đoạn C.</p>\n<p data-start=\"3879\" data-end=\"3977\"><strong data-start=\"3879\" data-end=\"3893\">Dẫn chứng:</strong><br data-start=\"3893\" data-end=\"3896\">“…the company took all employees and their families on a 2-day trip to Montreal…”</p>\n<p data-start=\"3979\" data-end=\"4052\"><strong data-start=\"3979\" data-end=\"3994\">Giải thích:</strong><br data-start=\"3994\" data-end=\"3997\">Công ty thưởng bằng chuyến trip cho gia đình nhân viên.</p>"}]', 2);
INSERT INTO public.questions VALUES ('7cb234c5-00f1-4d46-8610-aa34c32383cd', '6019e56c-13e9-452e-a401-f69d855393e9', 'fillup', 'Questions 31–40', '<p>Write <strong data-start="134" data-end="151">ONE WORD ONLY</strong> for each answer</p>
<p><span style="font-size: 14pt;"><strong>Developing food trends</strong></span></p>
<p>• The growth in interest in food fashions started with {photos | photographs | pictures} of food being shared on social media<br>• The UK food industry is constantly developing products which are new or different.<br>• Influencers on social media become ‘ambassadors’ for a brand.<br>– Sales of {vegan} food brands have grown rapidly this way.<br>• Supermarkets track demand for ingredients on social media.<br>– Famous {chefs | cooks} are influential.</p>
<p><strong>Marketing campaigns</strong><br>• The avocado:<br>– {journalists | reporters} were invited to visit growers in South Africa.<br>– Advertising focused on its {health} benefits.</p>
<p>• Oat milk:<br>– A Swedish brand’s media campaign received publicity by upsetting competitors.<br>– Promotion in the USA through {coffee} shops reduced the need for advertising.<br>– It appealed to consumers who are concerned about the {environment} .</p>
<p>• Norwegian skrei:<br>– has helped strengthen the {reputation} of Norwegian seafood.</p>
<p><strong>Ethical concerns</strong><br>• Quinoa:<br>– Its success led to an increase in its {price | cost} .<br>– Overuse of resources resulted in poor quality {soil} .</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('f332b8f6-9ac4-417d-8798-bf23bcf51f97', '6c0f8326-70f9-4ac7-8ac4-78a68c4be772', 'matching', ' Questions 14-19', '', '<p>Reading Passage 2 has six paragraphs.</p>
<p>Choose the correct heading for each paragraph from the list of headings below.</p>
<p>Choose the correct number, i-viii, in boxes 14-19.</p>', 'matching_headings', 'null', 'null', '{"layoutType": "heading", "summaryText": "", "answerOptions": [{"optionText": "i Objectives of the regeneration project "}, {"optionText": "ii Architectural details of the station buildings "}, {"optionText": "iii Features and facilities of the completed development "}, {"optionText": "iv The remains of a railway system "}, {"optionText": "v A positive evaluation of the finished project "}, {"optionText": "vi A way of controlling development costs "}, {"optionText": "vii Ways of crossing the site "}, {"optionText": "viii Reasons why the area had become neglected"}], "matchingItems": []}', 'null', '[{"content": "<h4 data-path-to-node=\"4\">14. Paragraph 1</h4>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Đáp án:</strong> <strong>iv. The remains of a railway system</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 1) Đoạn này mô tả vị trí, hình dạng tam giác (<em>triangular-shaped area</em>) và nguồn gốc của Gleisdreieck, là nơi giao nhau của các <strong>tuyến đường sắt</strong> (<em>intersection of different railway lines</em>) và có các nhà ga, nhà kho thuộc về hệ thống đường sắt cũ.</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong>Giải thích:</strong> Đoạn văn tập trung vào việc mô tả khu vực như là phần <strong>còn lại của một hệ thống đường sắt</strong>.</p>\n</li>\n</ul>\n<h4 data-path-to-node=\"7\">15. Paragraph 2</h4>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong>Đáp án:</strong> <strong>viii. Reasons why the area had become neglected</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 2) Đoạn này giải thích tại sao khu vực bị bỏ hoang (<em>run down and abandoned</em>): hệ thống đường sắt ngừng hoạt động (<em>ceased to be used</em>), bị dùng làm bãi rác (<em>rubbish tip</em>), và nằm gần Bức tường Berlin (<em>closeness of the wall</em>) khiến nó trở thành vùng đất vô chủ (<em>no-man’s-land</em>).</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong>Giải thích:</strong> Đoạn văn liệt kê các <strong>lý do khiến khu vực bị bỏ bê</strong> và suy tàn.</p>\n</li>\n</ul>\n<h4 data-path-to-node=\"10\">16. Paragraph 3</h4>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong>Đáp án:</strong> <strong>i. Objectives of the regeneration project</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 3) Đoạn này đề cập đến đề xuất của Nhà nước Berlin nhằm chuyển đổi Gleisdreieck thành một <strong>công viên đô thị lớn</strong> (<em>large urban park</em>), với mục tiêu tích hợp các khu vực đô thị khác nhau và phát triển các tiện ích mới.</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong>Giải thích:</strong> Đoạn văn trình bày <strong>mục tiêu của dự án tái tạo</strong> khu đô thị.</p>\n</li>\n</ul>\n<h4 data-path-to-node=\"13\">17. Paragraph 4</h4>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong>Đáp án:</strong> <strong>vii. Ways of crossing the site</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 4) Đoạn này mô tả cách khu vực được tổ chức xung quanh một đồng cỏ trung tâm, được cắt ngang bởi một <strong>lối đi bằng bê tông</strong> (<em>concrete footpath</em>) và một <strong>cặp đường ray</strong> (<em>pair of railway lines</em>).</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong>Giải thích:</strong> Đoạn văn tập trung vào <strong>các cách thức đi qua</strong> (<em>crossing</em>) khu đất, bao gồm đường ray, lối đi bộ và cầu thang bắc qua chênh lệch độ cao.</p>\n</li>\n</ul>\n<h4 data-path-to-node=\"16\">18. Paragraph 5</h4>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong>Đáp án:</strong> <strong>iii. Features and facilities of the completed development</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 5) Đoạn này liệt kê chi tiết các thành phần của công viên: sân hiên nắng (<em>sunny terrace</em>), rừng cây, xích đu (<em>swings</em>), nhà trẻ (<em>nursery</em>), sân thể thao (<em>sports fields</em>), bề mặt cho ván trượt (<em>skateboards</em>), và vườn cộng đồng (<em>community gardens</em>).</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong>Giải thích:</strong> Đoạn văn mô tả <strong>các đặc điểm và tiện ích</strong> (<em>features and facilities</em>) đã hoàn thành của công viên.</p>\n</li>\n</ul>\n<h4 data-path-to-node=\"19\">19. Paragraph 6</h4>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong>Đáp án:</strong> <strong>v. A positive evaluation of the finished project</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 6) Đoạn này bắt đầu bằng việc công viên được mở cửa và kết thúc bằng nhận định tích cực: “trái tim Berlin hiện có <strong>một lá phổi xanh mới</strong> (<em>new green lung</em>)” và đã bảo tồn được tinh thần của khu vực trước đây.</p>\n</li>\n<li>\n<p data-path-to-node=\"20,2,0\"><strong>Giải thích:</strong> Đoạn văn đưa ra <strong>đánh giá tích cực</strong> (<em>positive evaluation</em>) về dự án đã hoàn thành.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('5ac3626f-732d-4d7d-88c3-acafe2c7829d', 'c051746e-9115-4abe-9949-cdaf0419753f', 'fillup', 'Questions 31–40', '<p class="MsoNormal">Complete the notes below.</p>
<p class="MsoNormal">Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p class="MsoNormal" style="text-align: left;" align="center"><strong><span style="font-size: 14.0pt; line-height: 115%;">Science in the Future</span></strong></p>
<p class="MsoNormal" style="line-height: 150%;">Science were asked to predict changes in their own field in the next 50 years</p>
<p class="MsoNormal" style="line-height: 150%;"><strong>Computer science</strong></p>
<p class="MsoListParagraphCxSpFirst" style="text-indent: -.25in; line-height: 150%; mso-list: l1 level1 lfo1;"><!-- [if !supportLists]--><span style="font-family: Symbol; mso-fareast-font-family: Symbol; mso-bidi-font-family: Symbol;"><span style="mso-list: Ignore;">–<span style="font: 7.0pt ''Times New Roman'';">        </span></span></span><!--[endif]-->The invention of computers is as significant as the discovery of how to create and use {fire}</p>
<p class="MsoListParagraphCxSpLast" style="text-indent: -.25in; line-height: 150%; mso-list: l1 level1 lfo1;"><!-- [if !supportLists]--><span style="font-family: Symbol; mso-fareast-font-family: Symbol; mso-bidi-font-family: Symbol;"><span style="mso-list: Ignore;">–<span style="font: 7.0pt ''Times New Roman'';">        </span></span></span><!--[endif]-->Computer will be seen as being {intelligent}</p>
<p class="MsoNormal" style="line-height: 150%;"><strong>Psychology</strong></p>
<p class="MsoListParagraphCxSpFirst" style="text-indent: -.25in; line-height: 150%; mso-list: l0 level1 lfo2;"><!-- [if !supportLists]--><span style="font-family: Symbol; mso-fareast-font-family: Symbol; mso-bidi-font-family: Symbol;"><span style="mso-list: Ignore;">–<span style="font: 7.0pt ''Times New Roman'';">        </span></span></span><!--[endif]-->Research will become much more {varied} , and also more practical since more {women} will be working in the field.</p>
<p class="MsoListParagraphCxSpLast" style="text-indent: -.25in; line-height: 150%; mso-list: l0 level1 lfo2;"><!-- [if !supportLists]--><span style="font-family: Symbol; mso-fareast-font-family: Symbol; mso-bidi-font-family: Symbol;"><span style="mso-list: Ignore;">–<span style="font: 7.0pt ''Times New Roman'';">        </span></span></span><!--[endif]-->Imaging devices will give information about the behaviour of the {brain}.</p>
<p class="MsoNormal" style="line-height: 150%;"><strong>Genetics</strong></p>
<p class="MsoListParagraphCxSpFirst" style="text-indent: -.25in; line-height: 150%; mso-list: l3 level1 lfo3;"><!-- [if !supportLists]--><span style="font-family: Symbol; mso-fareast-font-family: Symbol; mso-bidi-font-family: Symbol;"><span style="mso-list: Ignore;">–<span style="font: 7.0pt ''Times New Roman'';">        </span></span></span><!--[endif]-->With increased life expectancy, it is important to consider the {quality} of elderly people’s lives.</p>
<p class="MsoListParagraphCxSpMiddle" style="text-indent: -.25in; line-height: 150%; mso-list: l3 level1 lfo3;"><!-- [if !supportLists]--><span style="font-family: Symbol; mso-fareast-font-family: Symbol; mso-bidi-font-family: Symbol;"><span style="mso-list: Ignore;">–<span style="font: 7.0pt ''Times New Roman'';">        </span></span></span><!--[endif]-->Knowledge of a person’s genome will indicate whether they are likely to be affected by a {disease} .</p>
<p class="MsoListParagraphCxSpLast" style="text-indent: -.25in; line-height: 150%; mso-list: l3 level1 lfo3;"><!-- [if !supportLists]--><span style="font-family: Symbol; mso-fareast-font-family: Symbol; mso-bidi-font-family: Symbol;"><span style="mso-list: Ignore;">–<span style="font: 7.0pt ''Times New Roman'';">        </span></span></span><!--[endif]-->The approach to treatment will be on an increasingly {personal} basis.</p>
<p class="MsoNormal" style="line-height: 150%;"><strong>Zoology</strong></p>
<p class="MsoListParagraphCxSpFirst" style="text-indent: -.25in; line-height: 150%; mso-list: l2 level1 lfo4;"><!-- [if !supportLists]--><span style="font-family: Symbol; mso-fareast-font-family: Symbol; mso-bidi-font-family: Symbol;"><span style="mso-list: Ignore;">–<span style="font: 7.0pt ''Times New Roman'';">        </span></span></span><!--[endif]-->People can explore the world via satellite.</p>
<p class="MsoListParagraphCxSpMiddle" style="text-indent: -.25in; line-height: 150%; mso-list: l2 level1 lfo4;"><!-- [if !supportLists]--><span style="font-family: Symbol; mso-fareast-font-family: Symbol; mso-bidi-font-family: Symbol;"><span style="mso-list: Ignore;">–<span style="font: 7.0pt ''Times New Roman'';">        </span></span></span><!--[endif]-->For example, it is possible to see the effects of the destruction of {forests} in East Africa.</p>
<p class="MsoListParagraphCxSpLast" style="text-indent: -.25in; line-height: 150%; mso-list: l2 level1 lfo4;"><!-- [if !supportLists]--><span style="font-family: Symbol; mso-fareast-font-family: Symbol; mso-bidi-font-family: Symbol;"><span style="mso-list: Ignore;">–<span style="font: 7.0pt ''Times New Roman'';">        </span></span></span><!--[endif]-->Such increased awareness should enable us to do more to look after the {planet}</p>', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h2 data-path-to-node=\"2\">PART 4</h2>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Lecturer:</strong> In this final lecture of our course on the history of science, I would like to look to the future and tell you about some predictions that have been made about scientific developments. The content for my talk is based on some research in which 30 scientific leaders were invited to comment on the developments that they envisage as likely to come about in their own discipline within 50 years. After summarizing some of their most interesting contributions for you, I&#8217;ll ask you to give me your opinions as to the likelihood of these changes occurring within this timescale. You may also like to suggest some other likely changes yourselves.</p>\n<p data-path-to-node=\"4\">So first, let&#8217;s start with <strong data-path-to-node=\"4\" data-index-in-node=\"27\">computer science</strong>, as this is clearly an area where there are bound to be dramatic developments. And even more significantly perhaps, these developments are likely to impact on every other field of learning. The invention of computers represents an enormous leap forward in the field of human endeavour. It could indeed be considered as being as momentous a development as when our predecessors in caves first learned to make <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"4\" data-index-in-node=\"452\">(31) fire</strong></span> and use it for all sorts of purposes. In the future, the computational revolution is certain to be generally recognized as a transformation as significant as, say, the Industrial Revolution.</p>\n<p data-path-to-node=\"5\">The computer scientists in the study I referred to felt that in the coming decades lives will be significantly enhanced by automated reasoning systems of different types. There was considerable agreement that people will increasingly perceive these computer systems as <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"5\" data-index-in-node=\"269\">(32) intelligent</strong>,</span> although many of these <span class=\"citation-177 citation-end-177\">will be deployed behind the scenes; others will be in the foreground serving in an elegant, often collaborative manner to help people do their jobs, to learn and teach, to reflect and remember, to plan and d</span>ecide.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p data-path-to-node=\"6\">Without going into further detail about this at this point, let&#8217;s turn to what predictions <strong data-path-to-node=\"6\" data-index-in-node=\"91\">psychologists</strong> had to make. Their key point was that psychological research would inevitably become increasingly <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"6\" data-index-in-node=\"203\">(33) varied</strong></span>. It would move into such areas as behavioral economics and social neuroscience. There is likely to be further expansion into domains with more practical relevance. As increasing numbers of <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"6\" data-index-in-node=\"404\">(34) women</strong></span> become research scientists, so areas such as health, environment, family and social identity will receive more attention. At the same time as they broaden their horizons, psychologists will also intensify their search to discover what exactly determines how we act. They will be assisted in this by imaging devices that will be inserted into the <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"6\" data-index-in-node=\"761\">(35) brain</strong></span> and provide a great deal of information about how it behaves. There should be some fascinating discoveries coming to light very soon.</p>\n<p data-path-to-node=\"7\">Another field that is currently undergoing enormous changes is that of <strong data-path-to-node=\"7\" data-index-in-node=\"71\">genetics</strong>. It is not new to suggest that average life expectancy is likely to continue rising in most countries. However today, geneticists emphasize that it is vital that the increasing number of the elderly in society must take <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"7\" data-index-in-node=\"300\">(36) quality</strong></span> of life into account. So how will genetics help this to happen?</p>\n<p data-path-to-node=\"8\">To start with, they hope to develop technologies that can sequence each person&#8217;s genome extremely cheaply. This information about our DNA enables healthcare providers to predict our likelihood of suffering from any particular <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"8\" data-index-in-node=\"226\">(37) disease</strong></span>. From there on, it is a matter of weighing up various factors with a view to determining what can be done to minimize each individual&#8217;s level of risk. With such information in hand, new treatments will be developed and the current &#8220;one size fits all&#8221; approach to healthcare will give way to a more <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"8\" data-index-in-node=\"537\">(38) personal</strong></span> approach.</p>\n<p data-path-to-node=\"9\">The final subject area that I wish to bring to your attention is that of <strong data-path-to-node=\"9\" data-index-in-node=\"73\">zoology</strong>. Once again, computers and technology have a key role to play here. Experts comment specifically on the importance of satellites for future developments in this field. These enable people to explore the world from their homes, offices and schools. It is now possible, for instance, to go online and see for yourself the abundant wildlife in one part of East Africa and, in the surrounding region, the harm people have done by destroying the <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"9\" data-index-in-node=\"522\">(39) forests</strong></span>, all supposedly in the name of development. Zoologists believe the breakthrough that lies ahead is how people act on such information as this. They hope that we will learn to connect our minds to our hearts and apply this knowledge to help protect our <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"9\" data-index-in-node=\"787\">(40) planet</strong>.</span> They express a clear hope that a greater understanding of the consequences of human short-sightedness will make people anxious to rectify what we can before it is too late.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('2a526197-1917-4016-aaf1-086b0ac10b6b', '6c0f8326-70f9-4ac7-8ac4-78a68c4be772', 'checkbox', 'Questions 20-21', NULL, '<p>Choose <strong>TWO </strong>correct answers.<br />Which <strong>TWO </strong>reasons are given for the choice of Gleisdreieck as a site for a park?</p>
', 'multiple_choice_many', 'null', '[{"option": "It was a habitat for some rare wildlife species.", "correct": false}, {"option": "It contained a particular tourist attraction.", "correct": true}, {"option": "It lay at the heart of the reunited city.", "correct": true}, {"option": "It was served by a major rail network.", "correct": false}, {"option": "It contained buildings which could be easily converted.", "correct": false}]', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"6\">20. It lay at the heart of the reunited city.</h3>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong>Đáp án:</strong> <strong>(Được chọn)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 2) “More importantly, the <strong>unification of the formerly divided city gave the zone more centrality</strong>, at which point it became imperative to identify a purpose for it.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong>Giải thích:</strong> Sự thống nhất (<em>unification</em>) đã mang lại <strong>vị trí trung tâm hơn</strong> (<em>more centrality</em>) cho khu vực, khiến việc quy hoạch nó trở nên bắt buộc và là lý do then chốt để chọn nó cho dự án tái phát triển lớn.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"8\">21. It contained a particular tourist attraction.</h3>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong>Đáp án:</strong> <strong>(Được chọn)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 2) “Shortly before the fall of the Berlin Wall, however, the <strong>German Museum of Technology was established there, attracting large numbers of visitors and giving visibility to the site</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong>Giải thích:</strong> Việc <strong>Bảo tàng Công nghệ Đức</strong> (<em>German Museum of Technology</em>) đã được thành lập tại đó đã thu hút du khách (<em>attracting large numbers of visitors</em>) và tăng khả năng hiển thị (<em>visibility</em>), khiến nó trở thành một điểm thu hút du lịch cụ thể và là yếu tố quan trọng khi xem xét mục đích sử dụng.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('d567af48-cb81-4c66-98e1-c265c6869f6e', '83f81a59-7c9b-4b10-b20a-c67071a7605a', 'matrix', 'Questions 23–26', '', '<p>Look at the following statements (Questions 23–26) and the list of researchers below</p>
<p>Match each statement with the correct researcher, <strong data-path-to-node="12" data-index-in-node="136">A, B</strong> or <strong data-path-to-node="12" data-index-in-node="144">C</strong>.</p>
<p>Write the correct letter, <strong data-path-to-node="12" data-index-in-node="173">A, B</strong> or <strong data-path-to-node="12" data-index-in-node="181">C</strong>, in boxes 23–26 on your answer sheet. <strong data-path-to-node="12" data-index-in-node="221">NB</strong> You may use any letter more than once.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": " List of researchers ", "matrixItems": [{"itemText": "The energy people have for exercising willpower is limited", "correctCategoryLetter": "A"}, {"itemText": "Even an unpleasant substance had a positive effect on willpower", "correctCategoryLetter": "A"}, {"itemText": "People’s responses to images changed after having to exercise self-control", "correctCategoryLetter": "C"}, {"itemText": "The sequence of options presented to consumers could be used to the consumers’ disadvantage", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "Roy F. Baumeister", "categoryLetter": "A"}, {"categoryText": "Jonathan Levav", "categoryLetter": "B"}, {"categoryText": "Todd Heatherton", "categoryLetter": "C"}]}', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">23. The energy people have for exercising willpower is limited</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án: {A} (Roy F. Baumeister)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “His [Baumeister] research demonstrated that there is a <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"67\">finite store</strong> of mental stamina for exerting self-control.” (Đoạn B).</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Roy Baumeister là người đưa ra lý thuyết rằng ý chí không phải là vô hạn. Ông chứng minh rằng chúng ta có một “kho lưu trữ hữu hạn” (<strong data-path-to-node=\"4,2,0\" data-index-in-node=\"145\">finite store</strong>, đồng nghĩa với <strong data-path-to-node=\"4,2,0\" data-index-in-node=\"174\">limited</strong>) năng lượng tinh thần để tự kiểm soát bản thân.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">24. Even an unpleasant substance had a positive effect on willpower</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án: {A} (Roy F. Baumeister)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “However, the experiment also included a control group who drank a <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"78\">tasteless</strong> low-fat dairy beverage. It provided them with <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"134\">no pleasure, yet it produced similar improvements</strong> in self-control.” (Đoạn D).</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong thí nghiệm của Baumeister, nhóm đối chứng uống một loại đồ uống nhạt nhẽo/không có vị (<strong data-path-to-node=\"6,2,0\" data-index-in-node=\"105\">tasteless</strong>, tương ứng với <strong data-path-to-node=\"6,2,0\" data-index-in-node=\"130\">unpleasant</strong>). Mặc dù nó không mang lại sự thích thú, nhưng vì có chứa glucose nên nó vẫn giúp cải thiện khả năng tự chủ của người tham gia.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">25. People’s responses to images changed after having to exercise self-control</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án: {C} (Todd Heatherton)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Next, these dieters… forcing themselves to <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"57\">suppress their laughter</strong>… When they were again shown pictures of food, further brain scans revealed <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"158\">more activity in the brain’s reward centre</strong>…” (Đoạn F).</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Todd Heatherton đã yêu cầu các đối tượng thử nghiệm phải nhịn cười (thực hiện tự kiểm soát). Kết quả quét não sau đó cho thấy phản ứng của họ đối với hình ảnh thức ăn đã thay đổi (trung tâm phần thưởng hoạt động mạnh hơn bình thường) do năng lượng tự chủ đã bị cạn kiệt.</p>\n</li>\n</ul>\n<p data-path-to-node=\"3\"><strong class=\"\" data-path-to-node=\"3\" data-index-in-node=\"0\">26. The sequence of options presented to consumers could be used to the consumers’ disadvantage</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong class=\"\" data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án: {B} (Jonathan Levav)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong class=\"\" data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “By </span><strong class=\"\" data-path-to-node=\"4,1,0\" data-index-in-node=\"15\">manipulating the order</strong><span class=\"\"> of the car buyers’ choices,</span><span class=\"\"> the researchers found that </span><strong class=\"\" data-path-to-node=\"4,1,0\" data-index-in-node=\"93\">customers would end up paying more</strong><span class=\"\">.</span><span class=\"\">” (Đoạn C).</span></p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong class=\"\" data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Jonathan Levav đã tiến hành nghiên cứu tại các đại lý xe hơi ở Đức.</span><span class=\"\"> Ông phát hiện ra rằng bằng cách thao túng/sắp xếp thứ tự đưa ra các lựa chọn (</span><strong class=\"\" data-path-to-node=\"4,2,0\" data-index-in-node=\"158\">manipulating the order</strong><span class=\"\"> tương ứng với </span><strong class=\"\" data-path-to-node=\"4,2,0\" data-index-in-node=\"195\">sequence of options</strong><span class=\"\">) từ dễ đến khó hoặc ngược lại,</span><span class=\"\"> người bán có thể khiến khách hàng rơi vào trạng thái mệt mỏi vì phải quyết định.</span><span class=\"\"> Kết quả là khách hàng thường chọn những phương án đắt tiền hơn hoặc chọn theo mặc định,</span><span class=\"\"> dẫn đến việc họ phải chi trả nhiều tiền hơn (</span><strong class=\"\" data-path-to-node=\"4,2,0\" data-index-in-node=\"460\">paying more</strong><span class=\"\"> tương ứng với </span><strong class=\"\" data-path-to-node=\"4,2,0\" data-index-in-node=\"486\">disadvantage</strong><span class=\"\"> – sự bất lợi về tài chính).</span></p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('43ba3e44-1dd0-451f-b0fd-768d78ad2856', 'fd336c53-5e69-4ad3-8b96-08c8be7a9179', 'matching', 'Questions 11–14', '', '<p>What feature of each of the following walks does the speaker recommend?</p>
<p>Choose <strong>FOUR </strong>correct answers, <strong>A-G</strong>, next to questions <strong>11-14</strong>.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Walks</strong></p>\n<p> </p>\n<p>Boundary Walk {seashore}</p>\n<p> </p>\n<p>Loop Track {views}</p>\n<p> </p>\n<p>Puriri Walk {picnic area}</p>\n<p> </p>\n<p>North Head {wildlife}</p>", "answerOptions": [{"optionText": "picnic area"}, {"optionText": "historic building"}, {"optionText": "flat paths"}, {"optionText": "seashore"}, {"optionText": "art works"}, {"optionText": "wildlife"}, {"optionText": "views"}], "matchingItems": []}', 'null', '[{"content": "<h2 data-path-to-node=\"2\">PART 2</h2>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Guide:</strong> Well morning everyone. Welcome to Palm Island. First I’ll run through the plan for the day so, um, the idea is that in the morning you’ll go for a walk. There are actually a number of different walks on the island, so I’ll describe each one and then you can choose.</p>\n<p data-path-to-node=\"4\">So there’s the <strong data-path-to-node=\"4\" data-index-in-node=\"15\">Boundary Walk</strong>. <span class=\"citation-89 citation-end-89\">This is one of the longer walks and it will appeal especially to people who love the coastline. And in fact, the tide is out today so it’ll be perfect for exploring the very old rock formations behind th<sup class=\"superscript\" data-turn-source-index=\"1\"><!----></sup></span>e <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"4\" data-index-in-node=\"235\">(11) beach (D: seashore)</strong></span>.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p data-path-to-node=\"5\">A good option is the <strong data-path-to-node=\"5\" data-index-in-node=\"21\">Loop Track</strong>. Now this is quite short, but don’t be misled by that because it’s very hilly and you need to be quite fit. The reward though is that you’ll be able to see right down the length of the island and even across to the mainland. It’ll be <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"5\" data-index-in-node=\"266\">(12) pretty as a picture (G: views)</strong> </span>on a fine day like today.</p>\n<p data-path-to-node=\"6\">There’s the <strong data-path-to-node=\"6\" data-index-in-node=\"12\">Puriri Walk</strong>, which follows one of the earliest trails that was built on the island. Unfortunately, the track’s been damaged slightly by a storm but it’s still passable. The nice thing is, about halfway there’s a <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"6\" data-index-in-node=\"224\">(13) table and chairs (A: picnic area)</strong></span>. They’ve recently been restored and painted in fact, and it’s a great place to eat your packed lunch and have a rest.</p>\n<p data-path-to-node=\"7\">You could also walk up to <strong data-path-to-node=\"7\" data-index-in-node=\"26\">North Head</strong>. This is an inland walk—you’ll hardly get a glimpse of the sea the whole way—but the attraction is you’ll pass through a large area of very old native bush. The <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"7\" data-index-in-node=\"198\">(14) number of birds is amazing (F: wildlife)</strong></span>, including several rare species. You’ll find some are quite tame, but please don’t give them any food.</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Guide:</strong> Okay well after your walk, the bus will take you to the Regional Park where you can relax for a couple of hours before going home. Now if you look at your maps of the Regional Park, I’ll just describe a few things you can do.</p>\n<p data-path-to-node=\"10\">So the bus will drop you at the park entrance, right at the bottom of the map. One interesting place is the <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"10\" data-index-in-node=\"108\">(15) bird colony</strong></span>. To get there from the park entrance, you go up the path to the lake. About halfway round the east side of the lake, you need to turn off and take the path all the way out to the coast. You’ll find the colony there, overlooking a little island <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"10\" data-index-in-node=\"369\">(D)</strong></span>.</p>\n<p data-path-to-node=\"11\">Now if you’d like a swim, remember that not all the beaches are really suitable in this wind. For the <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"11\" data-index-in-node=\"102\">(16) safest place (Safe swimming beach)</strong></span>, follow the path north from the park entrance, but before you get to the lake, turn right and go down there to the beach <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"11\" data-index-in-node=\"263\">(F)</strong></span>.</p>\n<p data-path-to-node=\"12\">Something that people find interesting is the <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"12\" data-index-in-node=\"46\">(17) old ship</strong></span>. It’s more than 100 years old. To get there, just north of the park entrance, you take the path which heads towards Okiwi Bay, then walk along the coast a little way before turning right and following that path over to Rocky Bay. You’ll see the wharf—go past that and the ship is just along there <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"12\" data-index-in-node=\"357\">(J)</strong></span>.</p>\n<p data-path-to-node=\"13\">A long walk but one that’s well worth it is up to <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"13\" data-index-in-node=\"50\">(18) Stony Batter</strong></span>. You follow the path right around the lake to the far side and keep heading north. But if you reach the water tower, you’ve gone too far. Before that, you want to turn off to your left and take the path to the coast <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"13\" data-index-in-node=\"284\">(E)</strong></span>.</p>\n<p data-path-to-node=\"14\">Now where else is there… oh yes, the <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"14\" data-index-in-node=\"39\">(19) Settlers’ Monument</strong></span>, that’s popular. So from the park entrance, take the first path on the left and follow it around behind Okiwi Bay. The Monument is out at the end there on the headland <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"14\" data-index-in-node=\"231\">(C)</strong></span>.</p>\n<p data-path-to-node=\"15\">Finally, if all this exercise has made you thirsty, there’s a <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"15\" data-index-in-node=\"62\">(20) kiosk</strong></span> where you can get hot and cold drinks. It’s easy to find beside the lake, right on the water’s edge <span style=\"text-decoration: underline;\"><strong data-path-to-node=\"15\" data-index-in-node=\"173\">(I)</strong></span>.</p>\n<p data-path-to-node=\"16\">Well now, if anyone has any questions feel free…</p>"}]', 0);
INSERT INTO public.questions VALUES ('9a77c18a-e3fd-4b1f-802e-8cf98ff1db9f', 'fd336c53-5e69-4ad3-8b96-08c8be7a9179', 'matrix', 'Questions 15–20', NULL, '<p>Label the map below.</p>
