', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": null, "matrixItems": [{"itemText": "Bird colony", "correctCategoryLetter": "D"}, {"itemText": "Safe swimming beach", "correctCategoryLetter": "F"}, {"itemText": "Old ship", "correctCategoryLetter": "J"}, {"itemText": "Stony Batter", "correctCategoryLetter": "E"}, {"itemText": "Settlers’ Monument", "correctCategoryLetter": "C"}, {"itemText": "Kiosk", "correctCategoryLetter": "I"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}, {"categoryText": "I", "categoryLetter": "I"}, {"categoryText": "J", "categoryLetter": "J"}]}', '[{"content": "<p>1</p>\n"}]', 1);
