', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Teachers</strong></p>\n<p><br>Bob Lacey {using a range of accents}</p>\n<p> </p>\n<p>Evelyn Chance {full use of the stage}</p>\n<p> </p>\n<p>Ted Winter {physical expression of character}</p>\n<p> </p>\n<p>Kevin Gray {following instructions}</p>\n<p> </p>\n<p>Dorothy Thomas {relaxation techniques}</p>", "answerOptions": [{"optionText": "use of own memories"}, {"optionText": "full use of the stage"}, {"optionText": "relaxation techniques"}, {"optionText": "physical expression of character"}, {"optionText": "play readings"}, {"optionText": "acting without preparation"}, {"optionText": "using a range of accents"}, {"optionText": "following instructions"}], "matchingItems": null}', 'null', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('f3a95ffc-3d84-49d4-b836-c98c7e0a69bd', '7848028c-bb18-47d7-a083-12b6b92268cf', 'radio', 'Questions 27 – 31', NULL, '<p>Choose <strong>YES </strong>if the statement agrees with the information given in the text, choose <strong>NO </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN </strong>if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "As expected, the artworks chosen for the exhibition reflect a narrow interpretation of landscape"}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The Academy rejected Australian suggestions for the subject of the exhibition"}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The colonial relationship meant that early Australian landscape painting followed the traditions of English landscape painting"}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The exhibition reflects the fact that Australian art developed its own particular qualities"}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Contemporary Australian artists have generally rejected British landscape traditions"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">27. As expected, the artworks chosen for the exhibition reflect a narrow interpretation of landscape.</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"8\">NO</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> “…this results in a <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"42\">flexible, wide-ranging notion of landscape</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả khẳng định triển lãm đem lại một khái niệm về phong cảnh “linh hoạt và rộng lớn”, trái ngược với từ “narrow” (hẹp hòi) trong câu hỏi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">28. The Academy rejected Australian suggestions for the subject of the exhibition.</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nhắc đến việc các chuyên gia Úc (như Mendelssohn) phê bình sự lựa chọn của Học viện, nhưng <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"114\">không hề đề cập</strong> đến việc phía Úc có đưa ra đề xuất nào và bị từ chối hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">29. The colonial relationship meant that early Australian landscape painting followed the traditions of English landscape painting.</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"8\">YES</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> “…it was <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"31\">inevitable</strong> during Australian art’s formative years that it would <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"96\">reflect Britain’s devotion to the beloved landscape</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Do mối quan hệ thuộc địa, nghệ thuật Úc thời kỳ đầu không thể tránh khỏi việc phản ánh sự sùng bái phong cảnh theo truyền thống của Anh.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">30. The exhibition reflects the fact that Australian art developed its own particular qualities.</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"8\">YES</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> Soriano nói: “What I wanted to show was how Australian art develops a <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"90\">real distinctiveness</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Triển lãm nhằm mục đích cho thấy sự phát triển mang tính bản sắc riêng (distinctiveness) của nghệ thuật Úc.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">31. Contemporary Australian artists have generally rejected British landscape traditions.</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc lấy ví dụ Shaun Gladwell vẫn quan tâm đến truyền thống (Turner/Romantic landscape). Tuy nhiên, bài <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"119\">không đưa ra nhận định chung</strong> cho toàn bộ các nghệ sĩ đương đại khác là họ có “tẩy chay” truyền thống Anh hay không.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('01eabf12-638e-4d4a-989e-06d2c7217b35', '7848028c-bb18-47d7-a083-12b6b92268cf', 'radio', 'Questions 32 – 36', NULL, '<p>Choose the correct answers</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "A. Australian landscape painting derives from the British tradition"}, {"content": "B. Australian landscape painting is more highly regarded than British"}, {"content": "C. Britain is still imposing its principles on Australian art"}, {"content": "D. British art cannot be compared to Australian art"}], "question": "What is the writer’s main point in the second paragraph?"}, {"correct": 1, "options": [{"content": "A. Modern Australian landscape painting has great variety"}, {"content": "B. The guidelines for the choice of work were very traditional"}, {"content": "C. Landscape painting remains a popular subject for British artists"}, {"content": "D. The British find the Australian landscape unsuitable as a subject"}], "question": "What does Joanna Mendelssohn find surprising?"}, {"correct": 0, "options": [{"content": "A. it adopts a subjective approach to depicting the landscape"}, {"content": "B. skateboarding is an inspiration to many Australian artists"}, {"content": "C. storms are a significant feature in the Australian landscape"}, {"content": "D. Bondi is an iconic Australian location"}], "question": "Shaun Gladwell’s work is included in the exhibition because"}, {"correct": 2, "options": [{"content": "A. It is not well known in London art circles"}, {"content": "B. Aboriginal landscape painting influenced Australian settlers"}, {"content": "C. It is part of the Australian art tradition and not independent of it"}, {"content": "D. Modem Aboriginal painting deals with changes to the landscape"}], "question": "What was the reason for Soriano including Aboriginal art in the exhibition?"}, {"correct": 0, "options": [{"content": "A. having an exhibition in London is not as important as it used to be"}, {"content": "B. young artists in Britain are not interested in Australian art"}, {"content": "C. art from Shanghai is more important than Australian art"}, {"content": "D. New York is still a preferred destination for young artists"}], "question": "By referring to China, Mendelssohn is making the point that"}]', 'null', 'null', 'null', '[{"content": "<p><strong class=\"\" data-path-to-node=\"2\" data-index-in-node=\"0\">32. What is the writer’s main point in the second paragraph?</strong></p>\n<ul data-path-to-node=\"3\">\n<li><strong class=\"\" data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong class=\"\" data-path-to-node=\"3,0,0\" data-index-in-node=\"8\">C. Britain is still imposing its principles on Australian art.</strong></li>\n<li><strong class=\"\" data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn 2,</span><span class=\"\"> dòng 6-8:</span><span class=\"\"> “…</span><span class=\"\">there is a suggestion that </span><strong class=\"\" data-path-to-node=\"3,1,0\" data-index-in-node=\"60\">British artistic values have directed this exhibition</strong><span class=\"\">,</span><span class=\"\"> rather than allowing Australia the freedom to demonstrate its maturity.</span><span class=\"\">“</span></li>\n<li><strong class=\"\" data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Tác giả nhấn mạnh rằng việc người Anh (Học viện Hoàng gia) tự ý chọn chủ đề phong cảnh cho thấy họ vẫn đang dùng các tiêu chuẩn nghệ thuật của mình để định hướng cho nghệ thuật Úc,</span><span class=\"\"> thay vì để nước Úc tự thể hiện bản sắc độc lập.</span></li>\n</ul>\n<p><strong class=\"\" data-path-to-node=\"4\" data-index-in-node=\"0\">33. What does Joanna Mendelssohn find surprising?</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"8\">B. The guidelines for the choice of work were very traditional.</strong></li>\n<li><strong class=\"\" data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn 3,</span><span class=\"\"> dòng 1-2:</span><span class=\"\"> “What Mendelssohn found surprising…</span><span class=\"\"> was the underlying </span><strong class=\"\" data-path-to-node=\"5,1,0\" data-index-in-node=\"86\">rules for the selection of works seemed to have been so conservative</strong><span class=\"\">.</span><span class=\"\">“</span></li>\n<li><strong class=\"\" data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Mendelssohn ngạc nhiên vì các quy tắc lựa chọn tác phẩm quá “conservative” (bảo thủ).</span><span class=\"\"> Trong bài thi IELTS,</span><span class=\"\"> “conservative” là từ đồng nghĩa phổ biến của </span><strong class=\"\" data-path-to-node=\"5,2,0\" data-index-in-node=\"164\">“traditional”</strong><span class=\"\"> (truyền thống/cũ kỹ).</span></li>\n</ul>\n<p><strong class=\"\" data-path-to-node=\"6\" data-index-in-node=\"0\">34. Shaun Gladwell’s work is included in the exhibition because</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong class=\"\" data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong class=\"\" data-path-to-node=\"7,0,0\" data-index-in-node=\"8\">A. it adopts a subjective approach to depicting the landscape.</strong></li>\n<li><strong class=\"\" data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn 6,</span><span class=\"\"> dòng 7-9:</span><span class=\"\"> “I was thinking about this tradition of Romantic landscape,</span><span class=\"\"> but </span><strong class=\"\" data-path-to-node=\"7,1,0\" data-index-in-node=\"93\">I wanted to make it personal</strong><span class=\"\">…</span><span class=\"\"> bring it to his experience and his world through skateboarding…</span><span class=\"\">“</span></li>\n<li><strong class=\"\" data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Tác phẩm video của Gladwell được chọn vì ông không chỉ vẽ phong cảnh khách quan mà đã đưa cái tôi,</span><span class=\"\"> trải nghiệm cá nhân (trượt ván) vào đó.</span><span class=\"\"> Cụm từ “make it personal” đồng nghĩa với </span><strong class=\"\" data-path-to-node=\"7,2,0\" data-index-in-node=\"192\">“subjective approach”</strong><span class=\"\"> (cách tiếp cận chủ quan).</span></li>\n</ul>\n<p><strong class=\"\" data-path-to-node=\"8\" data-index-in-node=\"0\">35. What was the reason for Soriano including Aboriginal art in the exhibition?</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong class=\"\" data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong class=\"\" data-path-to-node=\"9,0,0\" data-index-in-node=\"8\">C. It is part of the Australian art tradition and not independent of it.</strong></li>\n<li><strong class=\"\" data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn 8,</span><span class=\"\"> dòng 8-10:</span><span class=\"\"> “…</span><span class=\"\">I felt it was most accurate to be seen as </span><strong class=\"\" data-path-to-node=\"9,1,0\" data-index-in-node=\"76\">part of Australian art history, rather than a separate exhibition of its own</strong><span class=\"\">.</span><span class=\"\">“</span></li>\n<li><strong class=\"\" data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Soriano muốn đưa nghệ thuật thổ dân vào vì bà coi đó là một phần không thể tách rời của dòng chảy lịch sử nghệ thuật Úc,</span><span class=\"\"> chứ không phải một thứ nghệ thuật riêng biệt,</span><span class=\"\"> độc lập.</span></li>\n</ul>\n<p><strong class=\"\" data-path-to-node=\"10\" data-index-in-node=\"0\">36. By referring to China, Mendelssohn is making the point that</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong class=\"\" data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong class=\"\" data-path-to-node=\"11,0,0\" data-index-in-node=\"8\">A. having an exhibition in London is not as important as it used to be.</strong></li>\n<li><strong class=\"\" data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn cuối,</span><span class=\"\"> dòng 2-4:</span><span class=\"\"> “‘China is the most important art market in the world,</span><span class=\"\">’ she says.</span><span class=\"\"> ‘…</span><span class=\"\">My students…</span><span class=\"\"> are </span><strong class=\"\" data-path-to-node=\"11,1,0\" data-index-in-node=\"121\">less interested in going to London</strong><span class=\"\">.</span><span class=\"\">’”</span></li>\n<li><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc nhắc đến Trung Quốc (Thượng Hải) như một thị trường nghệ thuật hàng đầu thế giới là để chứng minh rằng London không còn là “trung tâm vũ trụ” của nghệ thuật như ngày xưa nữa. Tầm quan trọng của việc triển lãm tại London đã suy giảm.</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('1a7b0cea-fa3f-418d-8340-4dc561da4ed3', '7848028c-bb18-47d7-a083-12b6b92268cf', 'matching', 'Questions 37 – 40', NULL, '<p>Complete each sentence with the correct ending, A-F.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "standard", "summaryText": null, "answerOptions": [{"optionText": "A reflects the mood created by the natural environment"}, {"optionText": "B demonstrates that the dominant art form in Australia is landscape painting"}, {"optionText": "C demonstrates an understanding of the historical importance of the land"}, {"optionText": "D showcases a very small number of artists"}, {"optionText": "E  demonstrates a strong European flavour"}, {"optionText": "F  shows an acceptance of the unique qualities of Australian art"}], "matchingItems": [{"questionPart": "In spite of its conservatism, the Royal Academy exhibition", "correctAnswer": "F  shows an acceptance of the unique qualities of Australian art", "sectionContent": null}, {"questionPart": "Australian art of the early to mid-1800s", "correctAnswer": "E  demonstrates a strong European flavour", "sectionContent": null}, {"questionPart": "The modern work by Gladwell chosen for the exhibition", "correctAnswer": "A reflects the mood created by the natural environment", "sectionContent": null}, {"questionPart": "Including Aboriginal art in the exhibition", "correctAnswer": "C demonstrates an understanding of the historical importance of the land", "sectionContent": null}]}', 'null', '[{"content": "<p><strong class=\"\" data-path-to-node=\"2\" data-index-in-node=\"0\">37. In spite of its conservatism, the Royal Academy exhibition…</strong></p>\n<ul data-path-to-node=\"3\">\n<li><strong class=\"\" data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Đáp án: F. shows an acceptance of the unique qualities of Australian art.</strong></li>\n<li><strong class=\"\" data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong><span class=\"\"> “…</span><span class=\"\">the Academy is nevertheless </span><strong class=\"\" data-path-to-node=\"3,1,0\" data-index-in-node=\"52\">embracing the peculiarities</strong><span class=\"\"> (unique qualities) of Australian art from the mid-19th century onward…</span><span class=\"\">“</span></li>\n<li><strong class=\"\" data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Mặc dù bị chỉ trích là bảo thủ (conservative) khi chỉ chọn chủ đề phong cảnh,</span><span class=\"\"> triển lãm vẫn được ghi nhận là đã chấp nhận và tôn vinh những nét đặc thù,</span><span class=\"\"> riêng biệt (peculiarities) của nghệ thuật Úc.</span></li>\n</ul>\n<p><strong class=\"\" data-path-to-node=\"4\" data-index-in-node=\"0\">38. Australian art of the early to mid-1800s…</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Đáp án: E. demonstrates a strong European flavour.</strong></li>\n<li><strong class=\"\" data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong><span class=\"\"> “Certainly the </span><strong class=\"\" data-path-to-node=\"5,1,0\" data-index-in-node=\"35\">influence of English, French or German art</strong><span class=\"\"> is much more evident in the early periods,</span><span class=\"\"> in the early 1800s to mid-1800s…</span><span class=\"\">“</span></li>\n<li><strong class=\"\" data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Trong giai đoạn đầu đến giữa thế kỷ 19,</span><span class=\"\"> nghệ thuật Úc chịu ảnh hưởng nặng nề từ các trường phái hội họa của Anh,</span><span class=\"\"> Pháp và Đức,</span><span class=\"\"> tạo nên một “phong vị Châu Âu” (European flavour) đậm nét.</span></li>\n</ul>\n<p><strong class=\"\" data-path-to-node=\"6\" data-index-in-node=\"0\">39. The modern work by Gladwell chosen for the exhibition…</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong class=\"\" data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án: A. reflects the mood created by the natural environment.</strong></li>\n<li><strong class=\"\" data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong><span class=\"\"> “…</span><span class=\"\">I was interested in Turner and the idea of </span><strong class=\"\" data-path-to-node=\"7,1,0\" data-index-in-node=\"67\">atmosphere affecting vision</strong><span class=\"\">…</span><span class=\"\"> I was thinking about this tradition of </span><strong class=\"\" data-path-to-node=\"7,1,0\" data-index-in-node=\"137\">Romantic landscape</strong><span class=\"\">…</span><span class=\"\">“</span></li>\n<li><strong class=\"\" data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Tác phẩm của Gladwell lấy cảm hứng từ trường phái Lãng mạn (Romanticism),</span><span class=\"\"> vốn tập trung vào việc thể hiện cảm xúc và bầu không khí (mood/atmosphere) do thiên nhiên tạo ra.</span></li>\n</ul>\n<p><strong class=\"\" data-path-to-node=\"8\" data-index-in-node=\"0\">40. Including Aboriginal art in the exhibition…</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong class=\"\" data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án: C. demonstrates an understanding of the historical importance of the land.</strong></li>\n<li><strong class=\"\" data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 8):</strong><span class=\"\"> “One of the reasons landscape was seen as being the right theme was because </span><strong class=\"\" data-path-to-node=\"9,1,0\" data-index-in-node=\"96\">Australian art started in and on the landscape</strong><span class=\"\">.</span><span class=\"\">“</span></li>\n<li><strong class=\"\" data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Việc đưa nghệ thuật thổ dân vào triển lãm với chủ đề phong cảnh cho thấy Ban tổ chức hiểu rằng gốc rễ của nghệ thuật Úc gắn liền với vùng đất (land) ngay từ những ngày đầu tiên.</span></li>\n</ul>\n"}]', 2);
SET session_replication_role = DEFAULT;
